"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { registerSchema, RegisterFormData } from "@/types/auth";
import { authService } from "@/services/auth.service";
import { useAuthStore } from "@/hooks/useAuth";
import Button from "@/components/ui/Button";
import Link from "next/link";

export default function RegisterPage() {
  const router = useRouter();
  const login = useAuthStore((state) => state.login);
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [role, setRole] = useState<"student" | "company">("student");

  const {
    register,
    handleSubmit,
    formState: { errors },
    reset,
    setValue,
  } = useForm<RegisterFormData>({
    resolver: zodResolver(registerSchema),
    defaultValues: {
      role: "student",
    },
  });

  const handleRoleChange = (newRole: "student" | "company") => {
    setRole(newRole);
    setValue("role", newRole);
    reset({ role: newRole }); // Reset form fields when switching roles
  };

  const onSubmit = async (data: RegisterFormData) => {
    setIsLoading(true);
    setError("");
    try {
      const { user } = await authService.register(data);

      login(user);

      if (user.role === "student") {
        router.push("/student");
      } else {
        router.push("/company/dashboard");
      }
    } catch (err: any) {
      console.error("Registration error:", err);
      setError(err.message || "Registration failed. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen bg-gray-50 p-4">
      <div className="w-full max-w-md bg-white rounded-lg shadow-md p-8">
        <h1 className="text-2xl font-bold text-center mb-6">Create Account</h1>

        {error && (
          <div
            className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded relative mb-4"
            role="alert"
          >
            <span className="block sm:inline">{error}</span>
          </div>
        )}

        <div className="flex justify-center mb-6 space-x-4">
          <button
            type="button"
            onClick={() => handleRoleChange("student")}
            className={`px-4 py-2 rounded-md ${
              role === "student"
                ? "bg-blue-600 text-white"
                : "bg-gray-200 text-gray-700"
            }`}
          >
            Student
          </button>
          <button
            type="button"
            onClick={() => handleRoleChange("company")}
            className={`px-4 py-2 rounded-md ${
              role === "company"
                ? "bg-blue-600 text-white"
                : "bg-gray-200 text-gray-700"
            }`}
          >
            Company
          </button>
        </div>

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Email
            </label>
            <input
              type="email"
              {...register("email")}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="you@example.com"
            />
            {errors.email && (
              <p className="text-red-500 text-xs mt-1">
                {errors.email.message}
              </p>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Password
            </label>
            <input
              type="password"
              {...register("password")}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="********"
            />
            {errors.password && (
              <p className="text-red-500 text-xs mt-1">
                {errors.password.message}
              </p>
            )}
          </div>

          {role === "student" && (
            <>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Full Name
                </label>
                <input
                  type="text"
                  {...register("full_name")}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="John Doe"
                />
                {errors.full_name && (
                  <p className="text-red-500 text-xs mt-1">
                    {errors.full_name.message}
                  </p>
                )}
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  University (Optional)
                </label>
                <input
                  type="text"
                  {...register("university")}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="University Name"
                />
              </div>
            </>
          )}

          {role === "company" && (
            <>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Company Name
                </label>
                <input
                  type="text"
                  {...register("company_name")}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="Tech Corp"
                />
                {errors.company_name && (
                  <p className="text-red-500 text-xs mt-1">
                    {errors.company_name.message}
                  </p>
                )}
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Website URL (Optional)
                </label>
                <input
                  type="url"
                  {...register("website_url")}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                  placeholder="https://example.com"
                />
                {errors.website_url && (
                  <p className="text-red-500 text-xs mt-1">
                    {errors.website_url.message}
                  </p>
                )}
              </div>
            </>
          )}

          <Button type="submit" className="w-full" disabled={isLoading}>
            {isLoading ? "Creating Account..." : "Register"}
          </Button>
        </form>

        <div className="mt-4 text-center text-sm text-gray-600">
          Already have an account?{" "}
          <Link href="/login" className="text-blue-600 hover:underline">
            Login here
          </Link>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { companyService } from "@/services/company.service";
import { CompanyProfile } from "@/types/company";
import { Task } from "@/types/task";
import TaskCard from "@/components/ui/cards/TaskCard";
import { FiMapPin, FiGlobe, FiBriefcase, FiMail } from "react-icons/fi";

export default function CompanyProfilePage() {
  const params = useParams();
  const [profile, setProfile] = useState<CompanyProfile | null>(null);
  const [tasks, setTasks] = useState<Task[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        if (params.id) {
          const companyId = Number(params.id);
          const [profileData, tasksData] = await Promise.all([
            companyService.getCompanyById(companyId),
            companyService.getCompanyTasks(companyId),
          ]);
          setProfile(profileData);
          setTasks(tasksData);
        }
      } catch (error) {
        console.error("Failed to fetch company data:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [params.id]);

  if (loading) {
    return (
      <div className="min-h-screen mt-12 container mx-auto flex justify-center items-center text-gray-500">
        Yükleniyor...
      </div>
    );
  }

  if (!profile) {
    return (
      <div className="min-h-screen mt-12 container mx-auto flex justify-center items-center text-gray-500">
        Şirket bulunamadı.
      </div>
    );
  }

  return (
    <div className="min-h-screen mt-12 container mx-auto pb-12 px-4">
      {/* Company Header */}
      <div className="bg-white rounded-2xl p-8 border border-gray-100 shadow-sm relative overflow-hidden mb-8">
        <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 rounded-full -mr-16 -mt-16 blur-2xl"></div>

        <div className="flex flex-col md:flex-row gap-8 items-start">
          {/* Logo */}
          <div className="w-24 h-24 bg-gray-50 rounded-xl border border-gray-100 flex items-center justify-center text-3xl font-bold text-gray-300 shrink-0">
            {profile.logo_url ? (
              <img
                src={profile.logo_url}
                alt={profile.company_name}
                className="w-full h-full object-cover rounded-xl"
              />
            ) : (
              profile.company_name.charAt(0).toUpperCase()
            )}
          </div>

          {/* Info */}
          <div className="space-y-4 flex-grow">
            <div>
              <h1 className="text-3xl font-bold text-gray-900 mb-2">
                {profile.company_name}
              </h1>
              {profile.industry && (
                <span className="inline-block px-3 py-1 bg-gray-100 text-gray-600 rounded-full text-sm font-medium">
                  {profile.industry}
                </span>
              )}
            </div>

            <p className="text-gray-600 leading-relaxed max-w-3xl">
              {profile.description || "Şirket açıklaması bulunmuyor."}
            </p>

            <div className="flex flex-wrap gap-6 text-sm text-gray-500">
              {profile.location && (
                <div className="flex items-center gap-2">
                  <FiMapPin className="text-primary" />
                  <span>{profile.location}</span>
                </div>
              )}
              {profile.website_url && (
                <div className="flex items-center gap-2">
                  <FiGlobe className="text-primary" />
                  <a
                    href={profile.website_url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="hover:text-primary transition-colors"
                  >
                    {profile.website_url}
                  </a>
                </div>
              )}
              <div className="flex items-center gap-2">
                <FiMail className="text-primary" />
                <span>{profile.user.email}</span>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Active Tasks */}
      <div className="space-y-6">
        <div className="flex items-center gap-2 mb-6">
          <FiBriefcase className="text-2xl text-primary" />
          <h2 className="text-2xl font-bold text-gray-900">
            Açık İlanlar ({tasks.length})
          </h2>
        </div>

        {tasks.length > 0 ? (
          <div className="grid grid-cols-1 gap-6">
            {tasks.map((task) => (
              <TaskCard
                key={task.id}
                index={task.id}
                title={task.title}
                description={task.description}
                date={
                  task.created_at
                    ? new Date(task.created_at).toLocaleDateString("tr-TR")
                    : "Tarih bulunamadı"
                }
                companyName={profile.company_name}
                companyId={Number(params.id)}
                rating={0} // Default rating since it's not in the Task type yet
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-12 bg-gray-50 rounded-xl border border-dashed border-gray-200 text-gray-500">
            Bu şirkete ait açık ilan bulunmamaktadır.
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import FormCard from "@/components/ui/form/FormCard";
import FormRow from "@/components/ui/form/FormRow";
import FormField from "@/components/ui/form/FormField";
import FormButton from "@/components/ui/form/FormButton";
import RichTextEditor from "@/components/ui/form/RichTextEditor";
import { taskService } from "@/services/task.service";
import { submissionService } from "@/services/submission.service";
import { Task } from "@/types/task";
import { useToast } from "@/context/ToastContext";

const applySchema = z.object({
  submission_content: z.string().min(50, "Lütfen en az 50 karakterlik bir başvuru yazısı girin."),
});

type ApplyValues = z.infer<typeof applySchema>;

export default function ApplyPage() {
  const params = useParams();
  const router = useRouter();
  const taskId = Number(params.id);

  const [task, setTask] = useState<Task | null>(null);
  const [loading, setLoading] = useState(true);
  const { showToast } = useToast();

  const {
    control,
    handleSubmit,
    formState: { errors, isSubmitting },
  } = useForm<ApplyValues>({
    resolver: zodResolver(applySchema),
    defaultValues: {
      submission_content: "",
    },
  });

  useEffect(() => {
    const fetchTask = async () => {
      try {
        if (taskId) {
          const data = await taskService.getTaskById(taskId);
          setTask(data);
        }
      } catch (error) {
        showToast("Görev bilgileri alınamadı.", "error");
        router.push("/student/tasks");
      } finally {
        setLoading(false);
      }
    };
    fetchTask();
  }, [taskId, router]);

  const onSubmit = async (data: ApplyValues) => {
    try {
      await submissionService.createSubmission(taskId, {
        submission_content: data.submission_content,
      });
      showToast("Başvurunuz başarıyla gönderildi!", "success");
      router.push("/student/tasks");
    } catch (error: any) {
      showToast(error.response?.data?.message || "Başvuru sırasında bir hata oluştu.", "error");
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex justify-center items-center text-gray-500">
        Yükleniyor...
      </div>
    );
  }

  if (!task) {
    return (
      <div className="min-h-screen flex justify-center items-center text-gray-500">
        Görev bulunamadı.
      </div>
    );
  }

  return (
    <div className="min-h-screen container mx-auto mt-12 pb-12 max-w-4xl">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">Başvuru Yap: {task.title}</h1>
        <p className="text-gray-500">
          Bu göreve <strong>{task.company?.company_name}</strong> şirketinde başvuruyorsunuz. Neden bu görev için uygun olduğunuzu detaylıca anlatın.
        </p>
      </div>

      <FormCard
        title="Başvuru Bilgileri"
        subtitle="Lütfen başvuru mektubunuzu veya detaylarınızı aşağıya giriniz."
      >
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
          <FormRow>
            <FormField
              label="Başvuru Mektubu (Cover Letter)"
              error={errors.submission_content?.message}
              required
            >
              <Controller
                control={control}
                name="submission_content"
                render={({ field }) => (
                  <RichTextEditor
                    value={field.value}
                    onChange={field.onChange}
                    placeholder="Örn: Bu görevle ilgileniyorum çünkü..."
                  />
                )}
              />
            </FormField>
          </FormRow>

          <div className="flex justify-end pt-4 border-t border-gray-100">
            <FormButton
              type="button"
              variant="outline"
              onClick={() => router.back()}
              className="mr-3"
            >
              İptal
            </FormButton>
            <FormButton
              type="submit"
              variant="primary"
              isLoading={isSubmitting}
            >
              Başvuruyu Gönder
            </FormButton>
          </div>
        </form>
      </FormCard>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import MainSection from "@/components/ui/layouts/MainSection";
import MainSectionTitle from "@/components/ui/MainSectionTitle";
import Button from "@/components/ui/Button";
import Link from "next/link";
import {
  FiCalendar,
  FiAward,
  FiBriefcase,
  FiMapPin,
  FiGlobe,
} from "react-icons/fi";
import { taskService } from "@/services/task.service";
import { Task } from "@/types/task";
import { useAuthStore } from "@/hooks/useAuth";

export default function TaskDetailsPage() {
  const params = useParams();
  const router = useRouter();
  const { user } = useAuthStore();
  const [task, setTask] = useState<Task | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchTask = async () => {
      try {
        if (params.id) {
          const data = await taskService.getTaskById(Number(params.id));
          setTask(data);
        }
      } catch (error) {
        console.error("Failed to fetch task details:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchTask();
  }, [params.id]);

  if (loading) {
    return (
      <div className="min-h-screen mt-12 container mx-auto flex justify-center items-center text-gray-500">
        Yükleniyor...
      </div>
    );
  }

  if (!task) {
    return (
      <div className="min-h-screen mt-12 container mx-auto flex justify-center items-center text-gray-500">
        Görev bulunamadı.
      </div>
    );
  }

  // Format date
  const formattedDeadline = task.deadline
    ? new Date(task.deadline).toLocaleDateString("tr-TR", {
        year: "numeric",
        month: "long",
        day: "numeric",
      })
    : "Belirtilmemiş";

  const isCompanyOwner =
    user?.role === "company" && user?.id === task.company_user_id;

  return (
    <div className="min-h-screen mt-12 container mx-auto pb-12">
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Task Details */}
        <div className="lg:col-span-2 space-y-8">
          {/* Header */}
          <div className="bg-white rounded-2xl p-8 border border-gray-100 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 rounded-full -mr-16 -mt-16 blur-2xl"></div>

            <div className="relative">
              <span
                className={`inline-block px-3 py-1 rounded-full text-xs font-medium mb-4 ${
                  task.status === "open"
                    ? "bg-green-100 text-green-700"
                    : "bg-gray-100 text-gray-700"
                }`}
              >
                {task.status === "open" ? "Başvurulara Açık" : "Kapalı"}
              </span>

              <h1 className="text-3xl font-bold text-gray-900 mb-2">
                {task.title}
              </h1>

              <div className="flex items-center gap-2 text-gray-500 mb-6">
                <FiBriefcase className="text-primary" />
                <Link
                  href={`/companies/${task.company_user_id}`}
                  className="font-medium text-primary hover:underline"
                >
                  {task.company?.company_name}
                </Link>
                <span className="text-gray-300">•</span>
                <span className="text-sm">
                  Yayınlanma:{" "}
                  {new Date(task.created_at || Date.now()).toLocaleDateString(
                    "tr-TR"
                  )}
                </span>
              </div>

              <div className="flex flex-wrap gap-4 pt-4 border-t border-gray-100">
                <div className="flex items-center gap-2 text-gray-600 bg-gray-50 px-3 py-1.5 rounded-lg border border-gray-100">
                  <FiAward className="text-orange-500" />
                  <span className="text-sm font-medium">
                    {task.reward_type === "money"
                      ? `${task.reward_value || "Belirtilmemiş"} TL`
                      : task.reward_type === "internship"
                      ? "Staj İmkanı"
                      : "Sertifika"}
                  </span>
                </div>
                <div className="flex items-center gap-2 text-gray-600 bg-gray-50 px-3 py-1.5 rounded-lg border border-gray-100">
                  <FiCalendar className="text-blue-500" />
                  <span className="text-sm font-medium">
                    Son Başvuru: {formattedDeadline}
                  </span>
                </div>
              </div>
            </div>
          </div>

          {/* Description */}
          <MainSection title="Görev Detayları">
            <div 
              className="prose prose-sm sm:prose max-w-none text-gray-600 leading-relaxed break-words [&>p]:break-words [&_*]:whitespace-pre-wrap"
              dangerouslySetInnerHTML={{ __html: task.description || "Açıklama bulunmuyor." }}
            />
          </MainSection>

          {/* Skills */}
          <MainSection title="Gerekli Yetenekler">
            <div className="flex flex-wrap gap-2">
              {task.requiredSkills && task.requiredSkills.length > 0 ? (
                task.requiredSkills.map((skillObj: any, index: number) => (
                  <span
                    key={index}
                    className="bg-white border border-primary/20 text-primary px-4 py-2 rounded-full text-sm font-medium shadow-sm"
                  >
                    {skillObj.skill.name}
                  </span>
                ))
              ) : (
                <span className="text-gray-500 italic">Belirtilmemiş</span>
              )}
            </div>
          </MainSection>
        </div>

        {/* Right Column: Company Info & Actions */}
        <div className="lg:col-span-1 space-y-6">
          {/* Action Card */}
          <div className="bg-white rounded-2xl p-6 border border-gray-100 shadow-lg sticky top-24">
            <h3 className="text-lg font-bold text-gray-900 mb-4">İşlemler</h3>

            {user?.role === "student" ? (
              <Button
                variant="primary"
                className="w-full py-3 text-lg shadow-primary/25 shadow-lg mb-3"
                onClick={() => router.push(`/tasks/${task.id}/apply`)}
              >
                Başvur
              </Button>
            ) : isCompanyOwner ? (
              <div className="space-y-3">
                <Button
                  variant="primary"
                  className="w-full"
                  onClick={() => router.push(`/company/edit-task/${task.id}`)}
                >
                  Düzenle
                </Button>
                <Button
                  variant="outline"
                  className="w-full"
                  onClick={() =>
                    router.push(`/company/tasks/${task.id}/applicants`)
                  }
                >
                  Başvuruları Gör
                </Button>
              </div>
            ) : (
              <div className="text-center text-gray-500 text-sm bg-gray-50 p-3 rounded-lg">
                Bu göreve sadece öğrenciler başvurabilir.
              </div>
            )}

            <div className="mt-6 pt-6 border-t border-gray-100">
              <div className="flex items-center gap-3 mb-4">
                <div className="w-12 h-12 bg-gray-200 rounded-full flex items-center justify-center text-xl font-bold text-gray-500">
                  {task.company?.company_name?.charAt(0) || "C"}
                </div>
                <div>
                  <h4 className="font-bold text-gray-900">
                    {task.company?.company_name}
                  </h4>
                  {task.company?.website_url && (
                    <a
                      href={task.company.website_url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="text-xs text-primary hover:underline flex items-center gap-1"
                    >
                      <FiGlobe size={12} /> Web Sitesi
                    </a>
                  )}
                </div>
              </div>

              {task.company?.description && (
                <p className="text-sm text-gray-500 line-clamp-3 mb-4">
                  {task.company.description}
                </p>
              )}

              <Button
                variant="outline"
                className="w-full text-sm py-2"
                onClick={() =>
                  router.push(`/companies/${task.company_user_id}`)
                }
              >
                Şirket Profilini Gör
              </Button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import MainSection from "@/components/ui/layouts/MainSection";
import Breadcrumb from "@/components/ui/Breadcrumb";
import { submissionService } from "@/services/submission.service";
import { taskService } from "@/services/task.service";
import { Submission } from "@/types/submission";
import { Task } from "@/types/task";
import Button from "@/components/ui/Button";
import { useToast } from "@/context/ToastContext";
import {
  FiUser,
  FiCalendar,
  FiExternalLink,
  FiArrowLeft,
  FiX,
  FiCheck,
  FiMail,
  FiBookOpen,
} from "react-icons/fi";

/* ── Review Modal ── */
function ReviewModal({
  submission,
  onClose,
  onUpdate,
}: {
  submission: Submission;
  onClose: () => void;
  onUpdate: (updated: Submission) => void;
}) {
  const { showToast } = useToast();
  const [loading, setLoading] = useState<"approved" | "rejected" | null>(null);

  const handle = async (status: "approved" | "rejected") => {
    setLoading(status);
    try {
      const updated = await submissionService.updateSubmission(submission.id, status);
      onUpdate(updated);
      showToast(
        status === "approved" ? "Başvuru onaylandı." : "Başvuru reddedildi.",
        status === "approved" ? "success" : "error"
      );
      onClose();
    } catch {
      showToast("İşlem sırasında bir hata oluştu.", "error");
    } finally {
      setLoading(null);
    }
  };

  const statusLabel =
    submission.status === "approved"
      ? "Onaylandı"
      : submission.status === "rejected"
      ? "Reddedildi"
      : "Bekliyor";

  const statusCls =
    submission.status === "approved"
      ? "bg-green-100 text-green-700"
      : submission.status === "rejected"
      ? "bg-red-100 text-red-700"
      : "bg-yellow-100 text-yellow-700";

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      {/* backdrop */}
      <div className="absolute inset-0 bg-black/40" onClick={onClose} />

      <div className="relative bg-white rounded-2xl shadow-2xl max-w-lg w-full p-6 z-10">
        {/* close */}
        <button
          onClick={onClose}
          className="absolute top-4 right-4 text-gray-400 hover:text-gray-700 transition-colors"
        >
          <FiX className="w-5 h-5" />
        </button>

        {/* header */}
        <div className="flex items-center gap-4 mb-5">
          <div className="w-14 h-14 rounded-full bg-primary/10 text-primary font-bold text-xl flex items-center justify-center shrink-0">
            {submission.student.full_name.charAt(0)}
          </div>
          <div>
            <h3 className="text-lg font-bold text-gray-900">
              {submission.student.full_name}
            </h3>
            <div className="flex items-center gap-3 text-sm text-gray-500 flex-wrap">
              {submission.student.university && (
                <span className="flex items-center gap-1">
                  <FiBookOpen className="w-3.5 h-3.5" />
                  {submission.student.university}
                </span>
              )}
              <span className="flex items-center gap-1">
                <FiMail className="w-3.5 h-3.5" />
                {submission.student.user.email}
              </span>
            </div>
          </div>
        </div>

        {/* status */}
        <div className="flex items-center justify-between mb-4 border-b border-gray-100 pb-4">
          <div className="flex items-center gap-2">
            <span className="text-sm text-gray-500">Mevcut Durum:</span>
            <span className={`text-xs font-semibold px-2.5 py-1 rounded-full ${statusCls}`}>
              {statusLabel}
            </span>
          </div>
          {typeof submission.ai_match_score === 'number' && (
             <div className="flex items-center gap-2">
               <span className="text-sm text-gray-500">AI Eşleşme Oranı:</span>
               <span className="text-sm font-bold text-[#004d40]">% {submission.ai_match_score}</span>
             </div>
          )}
        </div>

        {/* Financials / Timeline if available */}
        {(submission.proposed_budget || submission.estimated_delivery_days) && (
          <div className="flex gap-6 mb-4">
            {submission.proposed_budget && (
              <div>
                 <p className="text-xs text-gray-400 mb-1">Talep Edilen Bütçe</p>
                 <p className="text-sm font-semibold text-gray-900">${submission.proposed_budget}</p>
              </div>
            )}
            {submission.estimated_delivery_days && (
              <div>
                 <p className="text-xs text-gray-400 mb-1">Teslim Süresi</p>
                 <p className="text-sm font-semibold text-gray-900">{submission.estimated_delivery_days} Gün</p>
              </div>
            )}
          </div>
        )}

        {/* submission content */}
        <div className="bg-gray-50 rounded-xl p-4 mb-5">
          <p className="text-xs font-semibold text-gray-400 uppercase tracking-wide mb-2">
            Başvuru İçeriği
          </p>
          <p className="text-sm text-gray-700 leading-relaxed whitespace-pre-wrap">
            {submission.submission_content || "İçerik belirtilmemiş."}
          </p>
        </div>

        {/* date */}
        <p className="text-xs text-gray-400 flex items-center gap-1 mb-6">
          <FiCalendar className="w-3.5 h-3.5" />
          Başvuru Tarihi:{" "}
          {new Date(submission.submitted_at || Date.now()).toLocaleDateString("tr-TR", {
            day: "2-digit",
            month: "long",
            year: "numeric",
          })}
        </p>

        {/* actions */}
        {submission.status === "pending" ? (
          <div className="flex gap-3">
            <button
              onClick={() => handle("approved")}
              disabled={!!loading}
              className="flex-1 flex items-center justify-center gap-2 bg-green-600 hover:bg-green-700 text-white font-semibold py-2.5 rounded-xl transition-colors disabled:opacity-60"
            >
              <FiCheck className="w-4 h-4" />
              {loading === "approved" ? "İşleniyor..." : "Onayla"}
            </button>
            <button
              onClick={() => handle("rejected")}
              disabled={!!loading}
              className="flex-1 flex items-center justify-center gap-2 bg-red-500 hover:bg-red-600 text-white font-semibold py-2.5 rounded-xl transition-colors disabled:opacity-60"
            >
              <FiX className="w-4 h-4" />
              {loading === "rejected" ? "İşleniyor..." : "Reddet"}
            </button>
          </div>
        ) : (
          <p className="text-center text-sm text-gray-400">
            Bu başvuru zaten işleme alındı.
          </p>
        )}
      </div>
    </div>
  );
}

