export default function TaskApplicantsPage() {
  const params = useParams();
  const router = useRouter();
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [task, setTask] = useState<Task | null>(null);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState<Submission | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [statusFilter, setStatusFilter] = useState<"all" | "pending" | "approved" | "rejected">("all");
  const [minAiScore, setMinAiScore] = useState<string>("");
  const [sortBy, setSortBy] = useState<"ai_desc" | "ai_asc" | "newest" | "oldest">("ai_desc");

  useEffect(() => {
    const fetchData = async () => {
      if (!params.id) return;
      try {
        const taskId = Number(params.id);
        const [taskData, submissionsData] = await Promise.all([
          taskService.getTaskById(taskId),
          submissionService.getTaskSubmissions(taskId),
        ]);
        const sortedSubmissions = submissionsData.sort((a: any, b: any) => (b.ai_match_score || 0) - (a.ai_match_score || 0));
        setTask(taskData);
        setSubmissions(sortedSubmissions);
      } catch (error) {
        console.error("Failed to fetch data:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [params.id]);

  const handleUpdate = (updated: Submission) => {
    setSubmissions((prev) =>
      prev.map((s) => (s.id === updated.id ? updated : s))
    );
  };

  const minAiScoreNumber = minAiScore === "" ? null : Number(minAiScore);

  const filteredSubmissions = submissions
    .filter((submission) => {
      const fullName = submission.student.full_name.toLowerCase();
      const email = submission.student.user.email.toLowerCase();
      const query = searchQuery.trim().toLowerCase();

      const matchesQuery =
        query.length === 0 ||
        fullName.includes(query) ||
        email.includes(query);

      const matchesStatus =
        statusFilter === "all" || submission.status === statusFilter;

      const score = typeof submission.ai_match_score === "number" ? submission.ai_match_score : 0;
      const matchesScore =
        minAiScoreNumber === null ||
        (!Number.isNaN(minAiScoreNumber) && score >= minAiScoreNumber);

      return matchesQuery && matchesStatus && matchesScore;
    })
    .sort((a, b) => {
      if (sortBy === "ai_desc") return (b.ai_match_score || 0) - (a.ai_match_score || 0);
      if (sortBy === "ai_asc") return (a.ai_match_score || 0) - (b.ai_match_score || 0);

      const dateA = new Date(a.submitted_at || Date.now()).getTime();
      const dateB = new Date(b.submitted_at || Date.now()).getTime();
      return sortBy === "newest" ? dateB - dateA : dateA - dateB;
    });

  if (loading)
    return (
      <div className="min-h-screen p-0 mx-auto flex justify-center items-center text-gray-500">
        Yükleniyor...
      </div>
    );

  return (
    <div className="min-h-screen p-0 mx-auto">
      {selected && (
        <ReviewModal
          submission={selected}
          onClose={() => setSelected(null)}
          onUpdate={handleUpdate}
        />
      )}

      <Breadcrumb items={[
        { label: "Panel", href: "/company/dashboard" },
        { label: "Görevlerim", href: "/company/tasks" },
        { label: task?.title || "Görev", href: `/company/tasks` },
        { label: "Başvurular", active: true },
      ]} />

      <MainSection hideHeader>
        {/* Header Row */}
        <div className="flex justify-between items-center mb-6">
          <div>
            <h2 className="text-base font-semibold text-gray-900">
              Başvuru Listesi
              {filteredSubmissions.length > 0 && (
                <span className="ml-2 text-xs font-normal text-gray-400">
                  ({filteredSubmissions.length} başvuru)
                </span>
              )}
            </h2>
            {task && (
              <Link
                href={`/company/tasks/${task.id}/details`}
                className="inline-flex items-center gap-1 text-xs text-primary underline underline-offset-2 hover:text-primary/80 transition-colors mt-0.5"
              >
                <FiExternalLink size={11} />
                Görev Detayları
              </Link>
            )}
          </div>
          <Button variant="outline" icon={FiArrowLeft} onClick={() => router.back()}>
            Geri Dön
          </Button>
        </div>

        <div className="bg-white border border-gray-100 rounded-xl p-4 mb-5">
          <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="İsim veya e-posta ara"
              className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20"
            />

            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value as "all" | "pending" | "approved" | "rejected")}
              className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-primary/20"
            >
              <option value="all">Tüm Durumlar</option>
              <option value="pending">Bekliyor</option>
              <option value="approved">Onaylandı</option>
              <option value="rejected">Reddedildi</option>
            </select>

            <input
              type="number"
              min={0}
              max={100}
              value={minAiScore}
              onChange={(e) => setMinAiScore(e.target.value)}
              placeholder="Min. AI Skor (%)"
              className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20"
            />

            <select
              value={sortBy}
              onChange={(e) => setSortBy(e.target.value as "ai_desc" | "ai_asc" | "newest" | "oldest")}
              className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-primary/20"
            >
              <option value="ai_desc">AI Skoru (Yüksekten Düşüğe)</option>
              <option value="ai_asc">AI Skoru (Düşükten Yükseğe)</option>
              <option value="newest">En Yeni Başvurular</option>
              <option value="oldest">En Eski Başvurular</option>
            </select>
          </div>
        </div>

        {filteredSubmissions.length === 0 ? (
          <div className="text-center py-12 text-gray-500">
            <FiUser size={48} className="mx-auto mb-4 text-gray-300" />
            <p>{submissions.length === 0 ? "Henüz başvuru bulunmamaktadır." : "Filtreye uygun başvuru bulunamadı."}</p>
          </div>
        ) : (
          <div className="space-y-4">
            {filteredSubmissions.map((submission) => (
              <div
                key={submission.id}
                className="border border-gray-100 rounded-xl p-6 hover:shadow-md transition-shadow bg-white"
              >
                <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
                  <div className="flex gap-4">
                    <div className="w-12 h-12 bg-primary/10 rounded-full flex items-center justify-center text-primary font-bold text-lg shrink-0">
                      {submission.student.full_name.charAt(0)}
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <h3 className="font-bold text-gray-900">
                          {submission.student.full_name}
                        </h3>
                        {typeof submission.ai_match_score === 'number' && (
                          <span className="px-2 py-0.5 bg-[#004d40]/10 text-[#004d40] text-xs font-bold rounded-full border border-[#004d40]/20" title="Yapay Zeka Yetenek Eşleşmesi">
                            % {submission.ai_match_score} AI Uyumlu
                          </span>
                        )}
                      </div>
                      <p className="text-sm text-gray-500 mt-0.5">
                        {submission.student.university ||
                          "Üniversite belirtilmemiş"}
                      </p>

                      {/* Metrikler (Bütçe / Zaman) */}
                      <div className="flex items-center gap-4 mt-2">
                        {submission.proposed_budget && (
                           <span className="text-sm font-medium text-gray-800 bg-gray-50 px-2 py-0.5 rounded border border-gray-100">
                             Bütçe: ${submission.proposed_budget}
                           </span>
                        )}
                        {submission.estimated_delivery_days && (
                           <span className="text-sm font-medium text-gray-800 bg-gray-50 px-2 py-0.5 rounded border border-gray-100">
                             Süre: {submission.estimated_delivery_days} Gün
                           </span>
                        )}
                      </div>

                      <div className="flex items-center gap-4 mt-3 text-sm text-gray-500">
                        <span className="flex items-center gap-1">
                          <FiCalendar size={14} />
                          {new Date(
                            submission.submitted_at || Date.now()
                          ).toLocaleDateString("tr-TR")}
                        </span>
                        <span
                          className={`px-2 py-0.5 rounded-full text-xs font-medium ${
                            submission.status === "approved"
                              ? "bg-green-100 text-green-700"
                              : submission.status === "rejected"
                              ? "bg-red-100 text-red-700"
                              : "bg-yellow-100 text-yellow-700"
                          }`}
                        >
                          {submission.status === "approved"
                            ? "Onaylandı"
                            : submission.status === "rejected"
                            ? "Reddedildi"
                            : "Bekliyor"}
                        </span>
                      </div>
                    </div>
                  </div>

                  <div className="flex flex-col gap-2 shrink-0">
                    <Button
                      variant="primary"
                      className="text-sm w-full md:w-auto"
                      onClick={() => setSelected(submission)}
                    >
                      İncele
                    </Button>
                  </div>
                </div>

                <div className="mt-4 pt-4 border-t border-gray-50 mb-4">
                  <p className="text-gray-600 text-sm line-clamp-2 italic">
                    {submission.submission_content || "İçerik yok"}
                  </p>
                </div>
              </div>
            ))}
          </div>
        )}
      </MainSection>
    </div>
  );
}

"use client";
import { useState, useEffect } from "react";
import { useRouter, useParams } from "next/navigation";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import Breadcrumb from "@/components/ui/Breadcrumb";
import RichTextEditor from "@/components/ui/form/RichTextEditor";
import {
  FormCard,
  FormInput,
  FormTextarea,
  FormSelect,
  FormRow,
  FormSection,
  FormButton,
} from "@/components/ui/form";
import { FiX, FiPlus, FiDollarSign, FiCalendar } from "react-icons/fi";
import { taskService } from "@/services/task.service";
import { TASK_CATEGORIES, getSubcategories } from "@/constants/categories";

const editTaskSchema = z.object({
  title: z.string().min(1, "Görev başlığı zorunludur"),
  description: z.string().min(10, "Açıklama zorunludur ve en az 10 karakter olmalı"),
  category: z.string().min(1, "Kategori seçimi zorunludur"),
  subcategory: z.string().min(1, "Alt kategori seçimi zorunludur"),
  hardSkills: z.array(z.object({
    skill: z.string().min(1),
    level: z.number().min(1).max(10),
    isRequired: z.boolean(),
    yearsOfExperience: z.number().min(0).optional(),
  })).min(1, "En az bir teknik yetenek eklenmeli"),
  softSkills: z.array(z.string()).optional(),
  reward_type: z.string().optional(),
  budget: z.string().optional(),
  currency: z.string().optional(),
  internship_duration: z.string().optional(),
  internship_department: z.string().optional(),
  internship_is_paid: z.string().optional(),
  certificate_name: z.string().optional(),
  certificate_issuer: z.string().optional(),
  positions: z.number().min(1, "Pozisyon sayısı zorunludur"),
  experience_level: z.string().min(1, "Seviye seçimi zorunludur"),
  preferred_major: z.string().optional(),
  work_type: z.string().min(1, "Çalışma tipi zorunludur"),
  deadline: z.string().optional(),
});

type EditTaskFormData = z.infer<typeof editTaskSchema>;

export default function EditTaskPage() {
  const router = useRouter();
  const params = useParams();
  const taskId = Number(params.id);

  const [hardSkills, setHardSkills] = useState<{ skill: string; level: number; isRequired: boolean; yearsOfExperience?: number }[]>([]);
  const [hardSkillInput, setHardSkillInput] = useState("");
  const [hardSkillLevel, setHardSkillLevel] = useState(5);
  const [hardSkillIsRequired, setHardSkillIsRequired] = useState(true);
  const [hardSkillYears, setHardSkillYears] = useState<number | "">("");
  const [softSkills, setSoftSkills] = useState<string[]>([]);
  const [softSkillInput, setSoftSkillInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [isFetching, setIsFetching] = useState(true);
  const [fetchError, setFetchError] = useState("");

  const {
    register,
    handleSubmit,
    watch,
    setValue,
    control,
    formState: { errors },
  } = useForm<EditTaskFormData>({
    resolver: zodResolver(editTaskSchema),
  });

  const selectedCategory = watch("category");
  const availableSubcategories = selectedCategory ? getSubcategories(selectedCategory) : [];
  const watchedRewardType = watch("reward_type");

  useEffect(() => {
    setValue("hardSkills", hardSkills, { shouldValidate: true });
  }, [hardSkills, setValue]);

  useEffect(() => {
    setValue("softSkills", softSkills, { shouldValidate: true });
  }, [softSkills, setValue]);

  // ─── Fetch existing task data ──────────────────────────────────────────────
  useEffect(() => {
    const fetchTask = async () => {
      try {
        const task = await taskService.getTaskById(taskId);

        setValue("title", task.title || "");
        setValue("description", task.description || "");
        setValue("reward_type", task.reward_type || "");
        setValue("category", task.category || "");
        setValue("subcategory", "");
        setTimeout(() => setValue("subcategory", task.subcategory || ""), 50);

        if (task.deadline) {
          setValue("deadline", new Date(task.deadline).toISOString().split("T")[0]);
        }

        if (task.positions) setValue("positions", Number(task.positions));
        if (task.experience_level) setValue("experience_level", task.experience_level);
        if (task.work_type) setValue("work_type", task.work_type);
        if (task.preferred_major) setValue("preferred_major", task.preferred_major);

        if (task.budget) setValue("budget", String(task.budget));
        if (task.currency) setValue("currency", task.currency);
        if (task.internship_duration) setValue("internship_duration", task.internship_duration);
        if (task.internship_department) setValue("internship_department", task.internship_department);
        if (task.internship_is_paid) setValue("internship_is_paid", task.internship_is_paid);
        if (task.certificate_name) setValue("certificate_name", task.certificate_name);
        if (task.certificate_issuer) setValue("certificate_issuer", task.certificate_issuer);

        // requiredSkills → hard skills with default values
        if (task.requiredSkills && Array.isArray(task.requiredSkills)) {
          setHardSkills(task.requiredSkills.map((s: { skill?: { name: string } | string; level?: number; isRequired?: boolean; yearsOfExperience?: number } | string) => {
            const skillSource = typeof s === "string" 
              ? s 
              : (typeof s.skill === "string" ? s.skill : s.skill?.name ?? "");
            return {
              skill: skillSource,
              level: typeof s === "object" && s !== null ? s.level ?? 5 : 5,
              isRequired: typeof s === "object" && s !== null ? s.isRequired ?? true : true,
              yearsOfExperience: typeof s === "object" && s !== null ? s.yearsOfExperience ?? undefined : undefined,
            }
          }));
        }

        // soft skills
        if (task.softSkills && Array.isArray(task.softSkills)) {
          setSoftSkills(task.softSkills.map((s: { name?: string } | string) => (typeof s === "string" ? s : s.name || "")));
        }
      } catch (err) {
        console.error("Failed to fetch task", err);
        setFetchError("Görev bilgileri yüklenemedi.");
      } finally {
        setIsFetching(false);
      }
    };

    if (taskId) fetchTask();
  }, [taskId, setValue]);

  // ─── Hard skill handlers ───────────────────────────────────────────────────
  const handleAddHardSkill = () => {
    if (hardSkillInput.trim() && !hardSkills.some(h => h.skill === hardSkillInput.trim())) {
      setHardSkills([...hardSkills, {
        skill: hardSkillInput.trim(),
        level: hardSkillLevel,
        isRequired: hardSkillIsRequired,
        yearsOfExperience: hardSkillYears !== "" ? Number(hardSkillYears) : undefined,
      }]);
      setHardSkillInput("");
      setHardSkillLevel(5);
      setHardSkillIsRequired(true);
      setHardSkillYears("");
    }
  };
  const handleRemoveHardSkill = (skill: string) => setHardSkills(hardSkills.filter(h => h.skill !== skill));

  // ─── Soft skill handlers ───────────────────────────────────────────────────
  const handleAddSoftSkill = () => {
    if (softSkillInput.trim() && !softSkills.includes(softSkillInput.trim())) {
      setSoftSkills([...softSkills, softSkillInput.trim()]);
      setSoftSkillInput("");
    }
  };
  const handleRemoveSoftSkill = (skill: string) => setSoftSkills(softSkills.filter(s => s !== skill));

  // ─── Submit ────────────────────────────────────────────────────────────────
  const onSubmit = async (data: EditTaskFormData) => {
    setIsLoading(true);
    try {
      // Clean up fields based on reward type to pass backend validation
      const cleanedData: Partial<EditTaskFormData> = { ...data };
      if (cleanedData.reward_type !== "money") {
        delete cleanedData.budget;
        delete cleanedData.currency;
      }
      if (cleanedData.reward_type !== "internship") {
        delete cleanedData.internship_duration;
        delete cleanedData.internship_department;
        delete cleanedData.internship_is_paid;
      }
      if (cleanedData.reward_type !== "certificate") {
        delete cleanedData.certificate_name;
        delete cleanedData.certificate_issuer;
      }

      // Remove any empty string values that are supposed to be ENUMs
      (["currency", "internship_is_paid", "experience_level", "preferred_major", "work_type"] as const).forEach((key) => {
          if (cleanedData[key] === "") {
             delete cleanedData[key];
          }
      });

      const payload = {
        ...cleanedData,
        hardSkills,
        softSkills,
        requiredSkills: hardSkills.map(h => h.skill),
        deadline: data.deadline ? new Date(data.deadline).toISOString() : undefined,
      };
      await taskService.updateTask(taskId, payload);
      router.push("/company/tasks");
    } catch (err) {
      const error = err as { response?: { data?: { message?: string } }, message?: string };
      console.error("Task update error:", error);
      setFetchError(error?.response?.data?.message || error?.message || "Görev güncellenirken bir hata oluştu.");
    } finally {
      setIsLoading(false);
    }
  };

  if (isFetching) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="flex flex-col items-center gap-3 text-gray-500">
          <div className="w-8 h-8 border-2 border-primary border-t-transparent rounded-full animate-spin" />
          <span className="text-sm">Görev yükleniyor...</span>
        </div>
      </div>
    );
  }

  if (fetchError) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="bg-red-50 border border-red-200 text-red-700 px-6 py-4 rounded-xl text-sm">{fetchError}</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen container mx-auto">
      <Breadcrumb
        items={[
          { label: "Görevler", href: "/company/tasks" },
          { label: "Görevi Düzenle" },
        ]}
      />

      <FormCard
        onSubmit={handleSubmit(onSubmit)}
        className="max-w-full"
        actions={
          <div className="flex justify-end gap-3 w-full">
            <FormButton type="button" variant="outline" onClick={() => router.back()}>
              Vazgeç
            </FormButton>
            <FormButton type="submit" isLoading={isLoading}>
              {isLoading ? "Güncelleniyor..." : "Güncelle"}
            </FormButton>
          </div>
        }
      >
        {/* ── Category & Subcategory ─────────────────────────────────────── */}
        <FormSection title="Kategori Bilgileri">
          <FormRow cols={2}>
            <FormSelect
              label="Kategori"
              name="category"
              options={TASK_CATEGORIES}
              value={watch("category") || ""}
              onChange={(val) => {
                setValue("category", val, { shouldValidate: true });
                setValue("subcategory", "");
              }}
              error={errors.category?.message}
              required
            />
            <FormSelect
              label="Alt Kategori"
              name="subcategory"
              options={availableSubcategories}
              value={watch("subcategory") || ""}
              onChange={(val) => setValue("subcategory", val, { shouldValidate: true })}
              disabled={!selectedCategory}
              placeholder={selectedCategory ? "Seçiniz" : "Önce kategori seçiniz"}
              error={errors.subcategory?.message}
              required
            />
          </FormRow>
        </FormSection>

        {/* ── Title ─────────────────────────────────────────────────────── */}
        <FormInput
          label="Görev Başlığı"
          {...register("title")}
          error={errors.title?.message}
          hint="Adayların ilgisini çekecek net ve anlaşılır bir başlık giriniz."
          placeholder="Örn: React Frontend Developer Stajyeri"
          required
        />

        {/* ── Description ───────────────────────────────────────────────── */}
        <Controller
          name="description"
          control={control}
          render={({ field }) => (
            <RichTextEditor
              label="Açıklama"
              value={field.value || ""}
              onChange={(val) => {
                if (val === "<p><br></p>") field.onChange("");
                else field.onChange(val);
              }}
              error={errors.description?.message}
              placeholder="Görev detaylarını, beklentileri ve sorumlulukları yazınız..."
              required
            />
          )}
        />

        {/* ── Hard Skills ───────────────────────────────────────────────── */}
        <div className="group">
          <label className="block text-sm font-semibold text-gray-700 mb-2">Teknik Yetenekler (Hard Skills)</label>
          {/* Row 1: skill input + level ring + add */}
          <div className="flex gap-2 mb-2">
            <div className="relative grow">
              <input
                type="text"
                value={hardSkillInput}
                onChange={(e) => setHardSkillInput(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && (e.preventDefault(), handleAddHardSkill())}
                className="w-full px-4 py-3 border border-gray-200 rounded-lg bg-gray-100/80 focus:ring-2 focus:ring-primary/20 focus:border-primary focus:bg-white outline-none transition-all hover:border-gray-300"
                placeholder="Yetenek ekle (örn: React, Python)"
              />
            </div>
            {/* Circular level ring */}
            {(() => {
              const r = 16;
              const circ = 2 * Math.PI * r;
              const progress = (hardSkillLevel / 10) * circ;
              const levelColor = hardSkillLevel <= 2 ? "#ef4444" : hardSkillLevel <= 4 ? "#fb923c" : hardSkillLevel <= 6 ? "#facc15" : hardSkillLevel <= 8 ? "#84cc16" : "#22c55e";
              return (
                <div className="flex items-center gap-1 px-3 border border-gray-300 rounded-lg shadow-sm hover:border-gray-400 transition-all bg-white self-stretch">
                  <button type="button" onClick={() => setHardSkillLevel(Math.max(1, hardSkillLevel - 1))} className="w-7 h-7 flex items-center justify-center rounded-full border border-gray-200 hover:border-gray-400 bg-white text-gray-500 hover:text-gray-800 transition-all text-sm font-bold shadow-sm">−</button>
                  <div className="relative flex items-center justify-center" style={{ width: 48, height: 48 }}>
                    <svg width="48" height="48" viewBox="0 0 44 44" className="-rotate-90">
                      <circle cx="22" cy="22" r={r} fill="none" stroke="#e5e7eb" strokeWidth="3" />
                      <circle cx="22" cy="22" r={r} fill="none" stroke={levelColor} strokeWidth="3" strokeLinecap="round" strokeDasharray={`${progress} ${circ}`} style={{ transition: "stroke-dasharray 0.25s ease, stroke 0.25s ease" }} />
                    </svg>
                    <div className="absolute inset-0 flex items-center justify-center">
                      <span className="text-[10px] font-semibold text-gray-700 tracking-tight leading-none" style={{ fontVariantNumeric: "tabular-nums" }}>
                        {hardSkillLevel}<span className="text-[8px] font-normal text-gray-400">/10</span>
                      </span>
                    </div>
                  </div>
                  <button type="button" onClick={() => setHardSkillLevel(Math.min(10, hardSkillLevel + 1))} className="w-7 h-7 flex items-center justify-center rounded-full border border-gray-200 hover:border-gray-400 bg-white text-gray-500 hover:text-gray-800 transition-all text-sm font-bold shadow-sm">+</button>
                </div>
              );
            })()}
            <button type="button" onClick={handleAddHardSkill} className="bg-primary text-white px-4 py-2 rounded-lg hover:bg-primary/90 transition-colors shadow-sm active:scale-95">
              <FiPlus size={20} />
            </button>
          </div>
          {/* Row 2: Required toggle + Years */}
          <div className="flex items-center gap-3 mb-3 pl-1">
            <div className="flex rounded-lg border border-gray-200 overflow-hidden text-xs font-semibold">
              <button type="button" onClick={() => setHardSkillIsRequired(true)}
                className={`px-3 py-1.5 transition-colors ${hardSkillIsRequired ? "bg-red-500 text-white" : "bg-white text-gray-500 hover:bg-gray-50"}`}>
                Zorunlu
              </button>
              <button type="button" onClick={() => setHardSkillIsRequired(false)}
                className={`px-3 py-1.5 border-l border-gray-200 transition-colors ${!hardSkillIsRequired ? "bg-blue-500 text-white" : "bg-white text-gray-500 hover:bg-gray-50"}`}>
                Tercih Edilen
              </button>
            </div>
            <div className="flex items-center gap-2 border border-gray-200 rounded-lg px-3 py-1.5 bg-white">
              <span className="text-xs text-gray-500 whitespace-nowrap">Deneyim (yıl)</span>
              <input
                type="number"
                min={0}
                max={20}
                value={hardSkillYears}
                onChange={(e) => setHardSkillYears(e.target.value === "" ? "" : Number(e.target.value))}
                className="w-12 text-xs text-center border-none outline-none bg-transparent text-gray-700 font-semibold"
                placeholder="-"
              />
            </div>
          </div>
          {hardSkills.length > 0 ? (
            <div className="flex flex-wrap gap-2 p-4 bg-gray-50 rounded-lg border border-gray-100 border-dashed min-h-[60px]">
              {hardSkills.map((h) => (
                <span key={h.skill} className="bg-white border text-xs px-3 py-1.5 rounded-full flex items-center gap-2 shadow-sm transition-all hover:shadow-md"
                  style={{ borderColor: h.isRequired ? "#fca5a5" : "#93c5fd", color: h.isRequired ? "#dc2626" : "#2563eb" }}>
                  <span className="w-1.5 h-1.5 rounded-full shrink-0" style={{ backgroundColor: h.isRequired ? "#ef4444" : "#3b82f6" }} title={h.isRequired ? "Zorunlu" : "Tercih Edilen"} />
                  <span className="text-gray-800 font-medium">{h.skill}</span>
                  {(() => {
                    const filled = Math.round(h.level / 10 * 5);
                    const color = h.level <= 2 ? "#ef4444" : h.level <= 4 ? "#fb923c" : h.level <= 6 ? "#facc15" : h.level <= 8 ? "#84cc16" : "#22c55e";
                    return (
                      <span className="flex items-end gap-0.5" title={`Seviye: ${h.level}/10`}>
                        {[1, 2, 3, 4, 5].map(i => (
                          <span key={i} style={{ width: 3, height: 4 + i * 2, borderRadius: 2, backgroundColor: i <= filled ? color : "#e5e7eb", display: "inline-block", transition: "background-color 0.2s" }} />
                        ))}
                      </span>
                    );
                  })()}
                  {h.yearsOfExperience !== undefined && h.yearsOfExperience > 0 && (
                    <span className="text-[10px] text-gray-400 font-normal">{h.yearsOfExperience}y</span>
                  )}
                  <button type="button" onClick={() => handleRemoveHardSkill(h.skill)} className="hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors ml-0.5"><FiX size={13} /></button>
                </span>
              ))}
            </div>
          ) : (
            <div className="text-sm text-gray-400 italic p-2">Henüz teknik yetenek eklenmedi.</div>
          )}
        </div>

        {/* ── Soft Skills ───────────────────────────────────────────────── */}
        <div className="group">
          <label className="block text-sm font-semibold text-gray-700 mb-2">Soft Skills (Opsiyonel)</label>
          <div className="flex gap-2 mb-3">
            <div className="relative grow">
              <input
                type="text"
                value={softSkillInput}
                onChange={(e) => setSoftSkillInput(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && (e.preventDefault(), handleAddSoftSkill())}
                className="w-full px-4 py-3 border border-gray-200 rounded-lg bg-gray-100/80 focus:ring-2 focus:ring-primary/20 focus:border-primary focus:bg-white outline-none transition-all hover:border-gray-300"
                placeholder="Soft skill ekle (örn: Takım Çalışması)"
              />
            </div>
            <button type="button" onClick={handleAddSoftSkill} className="bg-primary text-white px-4 py-2 rounded-lg hover:bg-primary/90 transition-colors shadow-sm active:scale-95"><FiPlus size={20} /></button>
          </div>
          {softSkills.length > 0 ? (
            <div className="flex flex-wrap gap-2 p-4 bg-gray-50 rounded-lg border border-gray-100 border-dashed min-h-10">
              {softSkills.map((s) => (
                <span key={s} className="bg-white border border-primary/20 text-primary px-3 py-1.5 rounded-full text-sm flex items-center gap-2 shadow-sm transition-all hover:shadow-md hover:border-primary/40">
                  {s}
                  <button type="button" onClick={() => handleRemoveSoftSkill(s)} className="hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors"><FiX size={14} /></button>
                </span>
              ))}
            </div>
          ) : (
            <div className="text-sm text-gray-400 italic p-2">Henüz soft skill eklenmedi.</div>
          )}
        </div>

        {/* ── Task Details ──────────────────────────────────────────────── */}
        <FormSection title="Görev Detayları">
          <FormRow cols={2}>
            <FormSelect
              label="Ödül Türü"
              name="reward_type"
              options={[
                { value: "money", label: "Para Ödülü" },
                { value: "internship", label: "Staj İmkanı" },
                { value: "certificate", label: "Sertifika" },
                { value: "recommendation", label: "Tavsiye Mektubu" },
                { value: "mentorship", label: "Mentorluk" },
              ]}
              value={watchedRewardType || ""}
              onChange={(val) => {
                setValue("reward_type", val);
                setValue("budget", "");
                setValue("currency", "");
                setValue("internship_duration", "");
                setValue("internship_department", "");
                setValue("internship_is_paid", "");
                setValue("certificate_name", "");
                setValue("certificate_issuer", "");
              }}
            />

            {watchedRewardType === "money" && (
              <>
                <FormInput label="Ödül Miktarı" type="number" min={0} step={1} {...register("budget")} icon={FiDollarSign} placeholder="Miktar giriniz" required />
                <FormSelect
                  label="Para Birimi"
                  name="currency"
                  options={[
                    { value: "TRY", label: "₺ Türk Lirası" },
                    { value: "USD", label: "$ Amerikan Doları" },
                    { value: "EUR", label: "€ Euro" },
                  ]}
                  value={watch("currency") || ""}
                  onChange={(val) => setValue("currency", val)}
                  placeholder="Para birimi seçiniz"
                />
              </>
            )}

            {watchedRewardType === "internship" && (
              <>
                <FormInput label="Staj Süresi" {...register("internship_duration")} placeholder="Örn: 3 ay, 1 yıl" icon={FiCalendar} required />
                <FormInput label="Staj Departmanı" {...register("internship_department")} placeholder="Örn: Yazılım Geliştirme" />
                <FormSelect
                  label="Ücretli mi?"
                  name="internship_is_paid"
                  options={[
                    { value: "paid", label: "Ücretli" },
                    { value: "unpaid", label: "Ücretsiz" },
                  ]}
                  value={watch("internship_is_paid") || ""}
                  onChange={(val) => setValue("internship_is_paid", val)}
                  placeholder="Seçiniz"
                />
              </>
            )}

            {watchedRewardType === "certificate" && (
              <>
                <FormInput label="Sertifika Adı" {...register("certificate_name")} placeholder="Örn: Frontend Geliştirici Sertifikası" required />
                <FormInput label="Veren Kurum" {...register("certificate_issuer")} placeholder="Örn: Şirket adı veya platform" />
              </>
            )}

            {watchedRewardType === "recommendation" && (
              <div className="md:col-span-2 bg-blue-50 border border-blue-200 rounded-xl px-5 py-4 text-sm text-blue-800 space-y-1">
                <p className="font-semibold">Tavsiye Mektubu</p>
                <p className="text-blue-600">Görevi başarıyla tamamlayan adaya şirket yetkilisi tarafından kişisel tavsiye mektubu yazılacaktır.</p>
              </div>
            )}

            {watchedRewardType === "mentorship" && (
              <div className="md:col-span-2 bg-purple-50 border border-purple-200 rounded-xl px-5 py-4 text-sm text-purple-800 space-y-1">
                <p className="font-semibold">Mentorluk Programı</p>
                <p className="text-purple-600">Görevi başarıyla tamamlayan aday, şirketin deneyimli uzmanlarından bire bir mentorluk desteği alacaktır.</p>
              </div>
            )}

            <FormInput label="Pozisyon Sayısı" type="number" min={1} {...register("positions", { valueAsNumber: true })} error={errors.positions?.message} placeholder="Kaç kişi alınacak?" required />

            <FormSelect
              label="Deneyim Seviyesi"
              name="experience_level"
              options={[
                { value: "beginner", label: "Başlangıç" },
                { value: "intermediate", label: "Orta" },
                { value: "advanced", label: "İleri" },
              ]}
              value={watch("experience_level") || ""}
              onChange={(val) => setValue("experience_level", val, { shouldValidate: true })}
              error={errors.experience_level?.message}
              required
            />

            <FormInput label="Tercih Edilen Bölüm (Opsiyonel)" {...register("preferred_major")} placeholder="Örn: Bilgisayar Mühendisliği" />

            <FormSelect
              label="Çalışma Tipi"
              name="work_type"
              options={[
                { value: "remote", label: "Uzaktan" },
                { value: "hybrid", label: "Hibrit" },
                { value: "onsite", label: "Ofiste" },
              ]}
              value={watch("work_type") || ""}
              onChange={(val) => setValue("work_type", val, { shouldValidate: true })}
              error={errors.work_type?.message}
              required
            />

            <FormInput label="Son Başvuru Tarihi" type="date" {...register("deadline")} icon={FiCalendar} />
          </FormRow>
        </FormSection>
      </FormCard>
    </div>
  );
}

"use client";
import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import Breadcrumb from "@/components/ui/Breadcrumb";
import RichTextEditor from "@/components/ui/form/RichTextEditor";
import {
  FormCard,
  FormInput,
  FormTextarea,
  FormSelect,
  FormRow,
  FormSection,
  FormButton,
} from "@/components/ui/form";
import { FiX, FiPlus, FiDollarSign, FiCalendar } from "react-icons/fi";
import { taskService } from "@/services/task.service";
import { TASK_CATEGORIES, getSubcategories } from "@/constants/categories";


const createTaskSchema = z.object({
  title: z.string().min(1, "Görev başlığı zorunludur"),
  description: z.string().min(10, "Açıklama zorunludur ve en az 10 karakter olmalı"),
  category: z.string().min(1, "Kategori seçimi zorunludur"),
  subcategory: z.string().min(1, "Alt kategori seçimi zorunludur"),
  hardSkills: z.array(z.object({
    skill: z.string().min(1),
    level: z.number().min(1).max(10),
    isRequired: z.boolean(),
    yearsOfExperience: z.number().min(0).optional(),
  })).min(1, "En az bir teknik yetenek eklenmeli"),
  softSkills: z.array(z.string()).optional(),
  reward_type: z.string().optional(),
  // money
  budget: z.string().optional(),
  currency: z.string().optional(),
  // internship
  internship_duration: z.string().optional(),
  internship_department: z.string().optional(),
  internship_is_paid: z.string().optional(),
  // certificate
  certificate_name: z.string().optional(),
  certificate_issuer: z.string().optional(),
  positions: z.number().min(1, "Pozisyon sayısı zorunludur"),
  experience_level: z.string().min(1, "Seviye seçimi zorunludur"),
  preferred_major: z.string().optional(),
  work_type: z.string().min(1, "Çalışma tipi zorunludur"),
  deadline: z.string().optional(),
});

type CreateTaskFormData = z.infer<typeof createTaskSchema>;

export default function NewTaskPage() {
  const router = useRouter();
  const [hardSkills, setHardSkills] = useState<{ skill: string; level: number; isRequired: boolean; yearsOfExperience?: number }[]>([]);
  const [hardSkillInput, setHardSkillInput] = useState("");
  const [hardSkillLevel, setHardSkillLevel] = useState(5);
  const [hardSkillIsRequired, setHardSkillIsRequired] = useState(true);
  const [hardSkillYears, setHardSkillYears] = useState<number | "">("");
  const [softSkills, setSoftSkills] = useState<string[]>([]);
  const [softSkillInput, setSoftSkillInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");

  const {
    register,
    handleSubmit,
    watch,
    setValue,
    control,
    formState: { errors },
  } = useForm<CreateTaskFormData>({
    resolver: zodResolver(createTaskSchema),
  });

  const selectedCategory = watch("category");
  const availableSubcategories = selectedCategory ? getSubcategories(selectedCategory) : [];
  const watchedRewardType = watch("reward_type");

  useEffect(() => {
    setValue("hardSkills", hardSkills, { shouldValidate: true });
  }, [hardSkills, setValue]);

  useEffect(() => {
    setValue("softSkills", softSkills, { shouldValidate: true });
  }, [softSkills, setValue]);


  // Hard skill handlers
  const handleAddHardSkill = () => {
    if (hardSkillInput.trim() && !hardSkills.some(h => h.skill === hardSkillInput.trim())) {
      setHardSkills([...hardSkills, {
        skill: hardSkillInput.trim(),
        level: hardSkillLevel,
        isRequired: hardSkillIsRequired,
        yearsOfExperience: hardSkillYears !== "" ? Number(hardSkillYears) : undefined,
      }]);
      setHardSkillInput("");
      setHardSkillLevel(5);
      setHardSkillIsRequired(true);
      setHardSkillYears("");
    }
  };
  const handleRemoveHardSkill = (skill: string) => {
    setHardSkills(hardSkills.filter(h => h.skill !== skill));
  };
  // Soft skill handlers
  const handleAddSoftSkill = () => {
    if (softSkillInput.trim() && !softSkills.includes(softSkillInput.trim())) {
      setSoftSkills([...softSkills, softSkillInput.trim()]);
      setSoftSkillInput("");
    }
  };
  const handleRemoveSoftSkill = (skill: string) => {
    setSoftSkills(softSkills.filter(s => s !== skill));
  };

  const onSubmit = async (data: CreateTaskFormData) => {
    // Manually trigger hardskills length validation check visually
    if (hardSkills.length === 0) {
      setError("En az bir teknik yetenek eklemelisiniz.");
      return;
    }

    setIsLoading(true);
    setError("");
    try {
      // Clean up fields based on reward type to pass backend validation
      const cleanedData: Partial<CreateTaskFormData> = { ...data };
      if (cleanedData.reward_type !== "money") {
        delete cleanedData.budget;
        delete cleanedData.currency;
      }
      if (cleanedData.reward_type !== "internship") {
        delete cleanedData.internship_duration;
        delete cleanedData.internship_department;
        delete cleanedData.internship_is_paid;
      }
      if (cleanedData.reward_type !== "certificate") {
        delete cleanedData.certificate_name;
        delete cleanedData.certificate_issuer;
      }

      // Remove any empty string values that are supposed to be ENUMs
      (["currency", "internship_is_paid", "experience_level", "preferred_major", "work_type"] as const).forEach((key) => {
          if (cleanedData[key] === "") {
             delete cleanedData[key];
          }
      });

      const payload = {
        ...cleanedData,
        hardSkills,
        softSkills,
        deadline: data.deadline ? new Date(data.deadline).toISOString() : undefined,
      };
      
      await taskService.createTask(payload);
      router.push("/company/tasks");
    } catch (err) {
      const error = err as { response?: { data?: { message?: string } }, message?: string };
      console.error("Task creation error:", error);
      setError(error?.response?.data?.message || error?.message || "Görev oluşturulurken bir hata oluştu.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen container mx-auto">
      {/* Breadcrumb for page navigation */}
      <Breadcrumb
        items={[
          { label: "Görevler", href: "/company/tasks" },
          { label: "Yeni Görev Yayınla" }
        ]}
      />
      
        <FormCard
          onSubmit={handleSubmit(onSubmit)}
          className="max-w-full"
          actions={
            <div className="flex justify-end gap-3 w-full">
              <FormButton
                type="button"
                variant="outline"
                onClick={() => router.back()}
              >
                Vazgeç
              </FormButton>
              <FormButton type="submit" isLoading={isLoading}>
                {isLoading ? "Yayınlanıyor..." : "Yayınla"}
              </FormButton>
            </div>
          }
        >
          {/* Category & Subcategory */}
          <FormSection title="Kategori Bilgileri">
            <FormRow cols={2}>
              <FormSelect
                label="Kategori"
                name="category"
                options={TASK_CATEGORIES}
                value={watch("category") || ""}
                onChange={(val) => {
                  setValue("category", val, { shouldValidate: true });
                  setValue("subcategory", "");
                }}
                error={errors.category?.message}
                required
              />
              <FormSelect
                label="Alt Kategori"
                name="subcategory"
                options={availableSubcategories}
                value={watch("subcategory") || ""}
                onChange={(val) => setValue("subcategory", val, { shouldValidate: true })}
                disabled={!selectedCategory}
                placeholder={selectedCategory ? "Seçiniz" : "Önce kategori seçiniz"}
                error={errors.subcategory?.message}
                required
              />
            </FormRow>
          </FormSection>

          {/* Title */}
          <FormInput
            label="Görev Başlığı"
            {...register("title")}
            error={errors.title?.message}
            hint="Adayların ilgisini çekecek net ve anlaşılır bir başlık giriniz."
            placeholder="Örn: React Frontend Developer Stajyeri"
            required
          />

          {/* Description */}
          <Controller
            name="description"
            control={control}
            render={({ field }) => (
              <RichTextEditor
                label="Açıklama"
                value={field.value || ""}
                onChange={(val) => {
                  // Ensure we don't save empty tags as real content if user clears it
                  if (val === "<p><br></p>") field.onChange("");
                  else field.onChange(val);
                }}
                error={errors.description?.message}
                placeholder="Görev detaylarını, beklentileri ve sorumlulukları yazınız..."
                required
              />
            )}
          />

          {/* Hard Skills with Level */}
          <div className="group">
            <label className="block text-sm font-semibold text-gray-700 mb-2">Teknik Yetenekler (Hard Skills)</label>
            {/* Row 1: skill input + level ring + add */}
            <div className="flex gap-2 mb-2">
              <div className="relative grow">
                <input
                  type="text"
                  value={hardSkillInput}
                  onChange={(e) => setHardSkillInput(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && (e.preventDefault(), handleAddHardSkill())}
                  className="w-full px-4 py-3 border border-gray-200 rounded-lg bg-gray-100/80 focus:ring-2 focus:ring-primary/20 focus:border-primary focus:bg-white outline-none transition-all hover:border-gray-300"
                  placeholder="Yetenek ekle (örn: React, Python)"
                />
              </div>
              {/* Circular skill level indicator */}
              {(() => {
                const r = 16;
                const circ = 2 * Math.PI * r;
                const progress = (hardSkillLevel / 10) * circ;
                const levelColor = hardSkillLevel <= 2 ? "#ef4444" : hardSkillLevel <= 4 ? "#fb923c" : hardSkillLevel <= 6 ? "#facc15" : hardSkillLevel <= 8 ? "#84cc16" : "#22c55e";
                return (
                  <div className="flex items-center gap-1 px-3 border border-gray-300 rounded-lg shadow-sm hover:border-gray-400 transition-all bg-white self-stretch">
                    <button type="button" onClick={() => setHardSkillLevel(Math.max(1, hardSkillLevel - 1))} className="w-7 h-7 flex items-center justify-center rounded-full border border-gray-200 hover:border-gray-400 bg-white text-gray-500 hover:text-gray-800 transition-all text-sm font-bold shadow-sm">−</button>
                    <div className="relative flex items-center justify-center" style={{ width: 48, height: 48 }}>
                      <svg width="48" height="48" viewBox="0 0 44 44" className="-rotate-90">
                        <circle cx="22" cy="22" r={r} fill="none" stroke="#e5e7eb" strokeWidth="3" />
                        <circle cx="22" cy="22" r={r} fill="none" stroke={levelColor} strokeWidth="3" strokeLinecap="round" strokeDasharray={`${progress} ${circ}`} style={{ transition: "stroke-dasharray 0.25s ease, stroke 0.25s ease" }} />
                      </svg>
                      <div className="absolute inset-0 flex items-center justify-center">
                        <span className="text-[10px] font-semibold text-gray-700 tracking-tight leading-none" style={{ fontVariantNumeric: "tabular-nums" }}>
                          {hardSkillLevel}<span className="text-[8px] font-normal text-gray-400">/10</span>
                        </span>
                      </div>
                    </div>
                    <button type="button" onClick={() => setHardSkillLevel(Math.min(10, hardSkillLevel + 1))} className="w-7 h-7 flex items-center justify-center rounded-full border border-gray-200 hover:border-gray-400 bg-white text-gray-500 hover:text-gray-800 transition-all text-sm font-bold shadow-sm">+</button>
                  </div>
                );
              })()}
              <button type="button" onClick={handleAddHardSkill} className="bg-primary text-white px-4 py-2 rounded-lg hover:bg-primary/90 transition-colors shadow-sm active:scale-95">
                <FiPlus size={20} />
              </button>
            </div>
            {/* Row 2: Required toggle + Years */}
            <div className="flex items-center gap-3 mb-3 pl-1">
              {/* Required / Preferred toggle */}
              <div className="flex rounded-lg border border-gray-200 overflow-hidden text-xs font-semibold">
                <button
                  type="button"
                  onClick={() => setHardSkillIsRequired(true)}
                  className={`px-3 py-1.5 transition-colors ${
                    hardSkillIsRequired
                      ? "bg-red-500 text-white"
                      : "bg-white text-gray-500 hover:bg-gray-50"
                  }`}
                >
                  Zorunlu
                </button>
                <button
                  type="button"
                  onClick={() => setHardSkillIsRequired(false)}
                  className={`px-3 py-1.5 border-l border-gray-200 transition-colors ${
                    !hardSkillIsRequired
                      ? "bg-blue-500 text-white"
                      : "bg-white text-gray-500 hover:bg-gray-50"
                  }`}
                >
                  Tercih Edilen
                </button>
              </div>
              {/* Years of experience */}
              <div className="flex items-center gap-2 border border-gray-200 rounded-lg px-3 py-1.5 bg-white">
                <span className="text-xs text-gray-500 whitespace-nowrap">Deneyim (yıl)</span>
                <input
                  type="number"
                  min={0}
                  max={20}
                  value={hardSkillYears}
                  onChange={(e) => setHardSkillYears(e.target.value === "" ? "" : Number(e.target.value))}
                  className="w-12 text-xs text-center border-none outline-none bg-transparent text-gray-700 font-semibold"
                  placeholder="-"
                />
              </div>
            </div>
            {hardSkills.length > 0 ? (
              <div className="flex flex-wrap gap-2 p-4 bg-gray-50 rounded-lg border border-gray-100 border-dashed min-h-[60px]">
                {hardSkills.map((h) => (
                  <span key={h.skill} className="bg-white border text-xs px-3 py-1.5 rounded-full flex items-center gap-2 shadow-sm transition-all hover:shadow-md"
                    style={{ borderColor: h.isRequired ? "#fca5a5" : "#93c5fd", color: h.isRequired ? "#dc2626" : "#2563eb" }}
                  >
                    {/* Required / Preferred dot */}
                    <span
                      className="w-1.5 h-1.5 rounded-full shrink-0"
                      style={{ backgroundColor: h.isRequired ? "#ef4444" : "#3b82f6" }}
                      title={h.isRequired ? "Zorunlu" : "Tercih Edilen"}
                    />
                    <span className="text-gray-800 font-medium">{h.skill}</span>
                    {/* Signal bars */}
                    {(() => {
                      const filled = Math.round(h.level / 10 * 5);
                      const color = h.level <= 2 ? "#ef4444" : h.level <= 4 ? "#fb923c" : h.level <= 6 ? "#facc15" : h.level <= 8 ? "#84cc16" : "#22c55e";
                      return (
                        <span className="flex items-end gap-0.5" title={`Seviye: ${h.level}/10`}>
                          {[1,2,3,4,5].map(i => (
                            <span key={i} style={{ width: 3, height: 4 + i * 2, borderRadius: 2, backgroundColor: i <= filled ? color : "#e5e7eb", display: "inline-block", transition: "background-color 0.2s" }} />
                          ))}
                        </span>
                      );
                    })()}
                    {/* Years badge */}
                    {h.yearsOfExperience !== undefined && h.yearsOfExperience > 0 && (
                      <span className="text-[10px] text-gray-400 font-normal">{h.yearsOfExperience}y</span>
                    )}
                    <button type="button" onClick={() => handleRemoveHardSkill(h.skill)} className="hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors ml-0.5"><FiX size={13} /></button>
                  </span>
                ))}
              </div>
            ) : (
              <div className="text-sm text-gray-400 italic p-2">Henüz teknik yetenek eklenmedi.</div>
            )}
          </div>
          {/* Soft Skills */}
          <div className="group">
            <label className="block text-sm font-semibold text-gray-700 mb-2">Soft Skills (Opsiyonel)</label>
            <div className="flex gap-2 mb-3">
              <div className="relative grow">
                <input
                  type="text"
                  value={softSkillInput}
                  onChange={(e) => setSoftSkillInput(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && (e.preventDefault(), handleAddSoftSkill())}
                  className="w-full px-4 py-3 border border-gray-200 rounded-lg bg-gray-100/80 focus:ring-2 focus:ring-primary/20 focus:border-primary focus:bg-white outline-none transition-all hover:border-gray-300"
                  placeholder="Soft skill ekle (örn: Takım Çalışması)"
                />
              </div>
              <button type="button" onClick={handleAddSoftSkill} className="bg-primary text-white px-4 py-2 rounded-lg hover:bg-primary/90 transition-colors shadow-sm active:scale-95"><FiPlus size={20} /></button>
            </div>
            {softSkills.length > 0 ? (
              <div className="flex flex-wrap gap-2 p-4 bg-gray-50 rounded-lg border border-gray-100 border-dashed min-h-10">
                {softSkills.map((s) => (
                  <span key={s} className="bg-white border border-primary/20 text-primary px-3 py-1.5 rounded-full text-sm flex items-center gap-2 shadow-sm transition-all hover:shadow-md hover:border-primary/40">
                    {s}
                    <button type="button" onClick={() => handleRemoveSoftSkill(s)} className="hover:text-red-500 hover:bg-red-50 rounded-full p-0.5 transition-colors"><FiX size={14} /></button>
                  </span>
                ))}
              </div>
            ) : (
              <div className="text-sm text-gray-400 italic p-2">Henüz soft skill eklenmedi.</div>
            )}
          </div>

          {/* Details Grid */}
          <FormSection title="Görev Detayları">
            <FormRow cols={2}>
              {/* Reward Type */}
              <FormSelect
                label="Ödül Türü"
                name="reward_type"
                options={[
                  { value: "money", label: "Para Ödülü" },
                  { value: "internship", label: "Staj İmkanı" },
                  { value: "certificate", label: "Sertifika" },
                  { value: "recommendation", label: "Tavsiye Mektubu" },
                  { value: "mentorship", label: "Mentorluk" },
                ]}
                value={watchedRewardType || ""}
                onChange={(val) => {
                  setValue("reward_type", val);
                  // reset reward-specific fields on type change
                  setValue("budget", "");
                  setValue("currency", "");
                  setValue("internship_duration", "");
                  setValue("internship_department", "");
                  setValue("internship_is_paid", "");
                  setValue("certificate_name", "");
                  setValue("certificate_issuer", "");
                }}
              />

              {/* ── Money ──────────────────────────────────────── */}
              {watchedRewardType === "money" && (
                <>
                  <FormInput
                    label="Ödül Miktarı"
                    type="number"
                    min={0}
                    step={1}
                    {...register("budget")}
                    icon={FiDollarSign}
                    placeholder="Miktar giriniz"
                    required
                  />
                  <FormSelect
                    label="Para Birimi"
                    name="currency"
                    options={[
                      { value: "TRY", label: "₺ Türk Lirası" },
                      { value: "USD", label: "$ Amerikan Doları" },
                      { value: "EUR", label: "€ Euro" },
                    ]}
                    value={watch("currency") || ""}
                    onChange={(val) => setValue("currency", val)}
                    placeholder="Para birimi seçiniz"
                  />
                </>
              )}

              {/* ── Internship ──────────────────────────────────── */}
              {watchedRewardType === "internship" && (
                <>
                  <FormInput
                    label="Staj Süresi"
                    {...register("internship_duration")}
                    placeholder="Örn: 3 ay, 1 yıl"
                    icon={FiCalendar}
                    required
                  />
                  <FormInput
                    label="Staj Departmanı"
                    {...register("internship_department")}
                    placeholder="Örn: Yazılım Geliştirme"
                  />
                  <FormSelect
                    label="Ücretli mi?"
                    name="internship_is_paid"
                    options={[
                      { value: "paid", label: "Ücretli" },
                      { value: "unpaid", label: "Ücretsiz" },
                    ]}
                    value={watch("internship_is_paid") || ""}
                    onChange={(val) => setValue("internship_is_paid", val)}
                    placeholder="Seçiniz"
                  />
                </>
              )}

              {/* ── Certificate ─────────────────────────────────── */}
              {watchedRewardType === "certificate" && (
                <>
                  <FormInput
                    label="Sertifika Adı"
                    {...register("certificate_name")}
                    placeholder="Örn: Frontend Geliştirici Sertifikası"
                    required
                  />
                  <FormInput
                    label="Veren Kurum"
                    {...register("certificate_issuer")}
                    placeholder="Örn: Şirket adı veya platform"
                  />
                </>
              )}

              {/* ── Recommendation ──────────────────────────────── */}
              {watchedRewardType === "recommendation" && (
                <div className="md:col-span-2 bg-blue-50 border border-blue-200 rounded-xl px-5 py-4 text-sm text-blue-800 space-y-1">
                  <p className="font-semibold">Tavsiye Mektubu</p>
                  <p className="text-blue-600">Görevi başarıyla tamamlayan adaya şirket yetkilisi tarafından kişisel tavsiye mektubu yazılacaktır.</p>
                </div>
              )}

              {/* ── Mentorship ──────────────────────────────────── */}
              {watchedRewardType === "mentorship" && (
                <div className="md:col-span-2 bg-purple-50 border border-purple-200 rounded-xl px-5 py-4 text-sm text-purple-800 space-y-1">
                  <p className="font-semibold">Mentorluk Programı</p>
                  <p className="text-purple-600">Görevi başarıyla tamamlayan aday, şirketin deneyimli uzmanlarından bire bir mentorluk desteği alacaktır.</p>
                </div>
              )}
              {/* Positions */}
              <FormInput
                label="Pozisyon Sayısı"
                type="number"
                min={1}
                {...register("positions", { valueAsNumber: true })}
                error={errors.positions?.message}
                placeholder="Kaç kişi alınacak?"
                required
              />
              {/* Experience Level */}
              <FormSelect
                label="Deneyim Seviyesi"
                name="experience_level"
                options={[
                  { value: "beginner", label: "Başlangıç" },
                  { value: "intermediate", label: "Orta" },
                  { value: "advanced", label: "İleri" },
                ]}
                value={watch("experience_level") || ""}
                onChange={(val) => setValue("experience_level", val, { shouldValidate: true })}
                error={errors.experience_level?.message}
                required
              />
              {/* Preferred Major */}
              <FormInput
                label="Tercih Edilen Bölüm (Opsiyonel)"
                {...register("preferred_major")}
                placeholder="Örn: Bilgisayar Mühendisliği"
              />
              {/* Work Type */}
              <FormSelect
                label="Çalışma Tipi"
                name="work_type"
                options={[
                  { value: "remote", label: "Uzaktan" },
                  { value: "hybrid", label: "Hibrit" },
                  { value: "onsite", label: "Ofiste" },
                ]}
                value={watch("work_type") || ""}
                onChange={(val) => setValue("work_type", val, { shouldValidate: true })}
                error={errors.work_type?.message}
                required
              />
              {/* Deadline */}
              <FormInput
                label="Son Başvuru Tarihi"
                type="date"
                {...register("deadline")}
                icon={FiCalendar}
              />
            </FormRow>
          </FormSection>
        </FormCard>
    </div>
  );
}

"use client";
import { useState, useEffect } from "react";
import SearchFilter, { SearchFilters } from "@/components/ui/SearchFilter";
import TasksBoard from "@/components/features/tasks/TasksBoard";
import { Task } from "@/components/features/tasks/types";
import { taskService } from "@/services/task.service";
import { studentService } from "@/services/student.service";
import { useAuthStore } from "@/hooks/useAuth";
import Button from "@/components/ui/Button";
import {
  FiCheckCircle,
  FiRefreshCw,
  FiZap,
} from "react-icons/fi";

interface StudentStats {
  completedTasks: number;
  totalApplications: number;
  averageRating: number;
  badgesEarned: number;
}

export default function StudentDashboard() {
  interface User {
    full_name?: string;
    // add other user properties if needed
  }
  const { user, _hasHydrated } = useAuthStore() as { user: User; _hasHydrated: boolean };
  const [tasks, setTasks] = useState<Task[]>([]);
  const [recommendedTasks, setRecommendedTasks] = useState<Task[]>([]);
  const [stats, setStats] = useState<StudentStats | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isRecommendedLoading, setIsRecommendedLoading] = useState(false);
  const [recommendedError, setRecommendedError] = useState("");
  const [viewMode, setViewMode] = useState<"all" | "recommended">("all");
  const [error, setError] = useState("");

  const mapBackendTask = (t: any): Task => ({
    id: t.id.toString(),
    title: t.title,
    tags: t.requiredSkills.map((s: any) => s.skill.name),
    rewardAmount: t.reward_amount || undefined,
    rewardType: t.reward_type || undefined,
    company: { id: t.company_user_id, name: t.company.company_name },
    createdAtLabel: t.created_at
      ? new Date(t.created_at).toLocaleDateString("tr-TR")
      : "Yeni",
    description: t.description || "",
    detailTitle: t.detail_title || "Görev Detayları",
    detailBody: t.detail_body || t.description || "",
    location: t.location || undefined,
    workType: t.work_type || undefined,
    matchPercentage: typeof t.matchPercentage === "number" ? t.matchPercentage : undefined,
  });

  useEffect(() => {
    fetchTasks();
    studentService
      .getMyStats()
      .then(setStats)
      .catch(() => {});
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // لا تعرض أي شيء حتى يتم التأكد من حالة المصادقة
  if (!_hasHydrated) {
    return null;
  }

  const name = user?.full_name || "Öğrenci";

  const fetchTasks = async (filters?: SearchFilters) => {
    setIsLoading(true);
    try {
      const backendTasks = await taskService.getTasks({
        search: filters?.keyword,
        category: filters?.category,
      });
      setTasks(backendTasks.map(mapBackendTask));
    } catch (err) {
      console.error(err);
      setError("Görevler yüklenirken bir hata oluştu.");
    } finally {
      setIsLoading(false);
    }
  };

  const fetchRecommendedTasks = async () => {
    setIsRecommendedLoading(true);
    setRecommendedError("");

    try {
      const backendTasks = await taskService.getRecommendedTasks();
      setRecommendedTasks(backendTasks.map(mapBackendTask));
      setViewMode("recommended");
    } catch (err) {
      console.error(err);
      setRecommendedError("AI eşleşen görevler alınamadı. Profil ve mikroservis bağlantısını kontrol edin.");
    } finally {
      setIsRecommendedLoading(false);
    }
  };

  // Duplicate useEffect removed to avoid calling hooks conditionally

  const handleSearch = (filters: SearchFilters) => {
    setViewMode("all");
    fetchTasks(filters);
  };

  const visibleTasks = viewMode === "recommended" ? recommendedTasks : tasks;

  if (isLoading && tasks.length === 0)
    return (
      <div className="flex items-center justify-center min-h-[50vh]">
        <div className="flex flex-col items-center gap-3">
          <div className="w-8 h-8 border-2 border-[#004d40] border-t-transparent rounded-full animate-spin" />
          <p className="text-gray-500 text-sm">Yükleniyor...</p>
        </div>
      </div>
    );
  if (error)
    return (
      <div className="flex items-center justify-center min-h-[50vh]">
        <p className="text-red-500">{error}</p>
      </div>
    );

  return (
    <div className="max-w-6xl mx-auto px-4 py-8 space-y-8">
      {/* Welcome Banner */}
      <div className="relative overflow-hidden bg-linear-to-br from-[#004d40] via-[#00695c] to-[#004d40] rounded-2xl p-8 text-white">
        {/* Decorative elements */}
        <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/3" />
        <div className="absolute bottom-0 left-0 w-40 h-40 bg-[#fbb049]/10 rounded-full translate-y-1/2 -translate-x-1/4" />

        <div className="relative z-10">
          <p className="text-white/70 text-sm font-medium mb-1">Hoş Geldin 👋</p>
          <h1 className="text-2xl md:text-3xl font-bold mb-2">{name}</h1>
          <p className="text-white/60 text-sm max-w-lg">
            Yeteneklerine uygun görevleri keşfet, başvur ve kariyerini inşa et.
          </p>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5 md:p-6">
        <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4">
          <div>
            <div className="inline-flex items-center gap-2 rounded-full bg-[#004d40]/10 px-3 py-1 text-xs font-semibold text-[#004d40] mb-3">
              <FiZap /> AI Eşleşme Testi
            </div>
            <h2 className="text-lg font-bold text-gray-900">Frontend'den eşleşen görevleri çek</h2>
            <p className="text-sm text-gray-500 mt-1 max-w-2xl">
              Bu bölüm doğrudan backend'deki <span className="font-medium text-gray-700">/tasks/recommended</span> endpoint'ini çağırır ve mikroservis skorunu kartlarda gösterir.
            </p>
          </div>
          <div className="flex items-center gap-3">
            <Button
              type="button"
              variant={viewMode === "recommended" ? "primary" : "outline"}
              onClick={fetchRecommendedTasks}
              isLoading={isRecommendedLoading}
            >
              Eşleşen Görevleri Getir
            </Button>
            <Button
              type="button"
              variant={viewMode === "all" ? "primary" : "outline"}
              onClick={() => setViewMode("all")}
              icon={FiRefreshCw}
            >
              Tüm Görevler
            </Button>
          </div>
        </div>
        {recommendedError && (
          <p className="mt-4 rounded-lg border border-red-100 bg-red-50 px-4 py-3 text-sm text-red-600">
            {recommendedError}
          </p>
        )}
      </div>

      {/* Search & Tasks */}
      <SearchFilter onSearch={handleSearch} />
      {visibleTasks.length === 0 ? (
        <div className="bg-white rounded-xl border border-gray-100 p-12 text-center">
          <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-4">
            <FiCheckCircle className="w-8 h-8 text-gray-300" />
          </div>
          <p className="text-gray-500">
            {viewMode === "recommended"
              ? "Henüz eşleşen görev bulunamadı."
              : "Henüz görev bulunmamaktadır."}
          </p>
        </div>
      ) : (
        <TasksBoard tasks={visibleTasks} />
      )}
    </div>
  );
}

