                className={`flex items-center gap-2 px-5 py-4 text-sm font-medium transition-all relative ${
                  isActive
                    ? "text-[#004d40]"
                    : "text-gray-400 hover:text-gray-600"
                }`}
              >
                <tab.icon className="w-4 h-4" />
                {tab.label}
                {isActive && (
                  <span className="absolute bottom-0 left-0 w-full h-0.5 bg-[#004d40] rounded-t-full" />
                )}
              </button>
            );
          })}
        </div>

        <div className="p-8">
          {/* Profile Section */}
          {activeSection === "profile" && (
            <form
              onSubmit={handleSubmit(onProfileSubmit as any)}
              className="space-y-6 max-w-2xl"
            >
              {/* Full Name */}
              <div className="group">
                <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                  <FiUser className="w-4 h-4" />
                  Ad Soyad
                </label>
                <input
                  type="text"
                  {...register("full_name")}
                  className={inputClass}
                  placeholder="Ad Soyad"
                />
                {errors.full_name && (
                  <p className="text-red-500 text-sm mt-1">
                    {errors.full_name.message}
                  </p>
                )}
              </div>

              {/* University */}
              <div className="group">
                <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                  <FiBook className="w-4 h-4" />
                  Üniversite / Okul
                </label>
                <input
                  type="text"
                  {...register("university")}
                  className={inputClass}
                  placeholder="Üniversite Adı"
                />
              </div>

              {/* Major & Grad Year */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <div className="group">
                  <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                    <FiBook className="w-4 h-4" />
                    Bölüm / Uzmanlık
                  </label>
                  <input
                    type="text"
                    {...register("major")}
                    className={inputClass}
                    placeholder="Örn: Yazılım Mühendisliği"
                  />
                </div>
                <div className="group">
                  <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                    <FiBook className="w-4 h-4" />
                    Mezuniyet Yılı
                  </label>
                  <input
                    type="number"
                    {...register("graduation_year")}
                    className={inputClass}
                    placeholder="Örn: 2025"
                  />
                </div>
              </div>

              {/* Categories & Availability */}
              <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                <div className="group">
                  <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                    <FiBriefcase className="w-4 h-4" />
                    İlgi Alanları
                  </label>
                  <input
                    type="text"
                    {...register("categories_of_interest")}
                    className={inputClass}
                    placeholder="Örn: Yazılım, Tasarım (Virgülle ayırın)"
                  />
                </div>
                <div className="group">
                  <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                    <FiUser className="w-4 h-4" />
                    Müsaitlik Durumu
                  </label>
                  <select
                    {...register("availability_status")}
                    className={`${inputClass} bg-white`}
                  >
                    <option value="available">Müsaitim (İş/Görev arıyorum)</option>
                    <option value="busy">Meşgulüm</option>
                  </select>
                </div>
              </div>

              {/* Bio */}
              <div className="group">
                <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                  <FiFileText className="w-4 h-4" />
                  Hakkımda
                </label>
                <textarea
                  {...register("bio")}
                  rows={4}
                  className={`${inputClass} resize-none`}
                  placeholder="Kendinizden bahsedin..."
                />
                {errors.bio && (
                  <p className="text-red-500 text-sm mt-1">
                    {errors.bio.message}
                  </p>
                )}
              </div>

              {/* Phone */}
              <div className="group">
                <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                  <FiPhone className="w-4 h-4" />
                  Telefon Numarası
                </label>
                <input
                  type="text"
                  {...register("phone")}
                  className={inputClass}
                  placeholder="05XX XXX XX XX"
                />
              </div>

              {/* Social Links */}
              <div className="pt-4 border-t border-gray-100">
                <h3 className="text-sm font-semibold text-gray-800 mb-4">
                  Sosyal Bağlantılar
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                  <div className="group">
                    <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                      <FiLinkedin className="w-4 h-4" />
                      LinkedIn
                    </label>
                    <input
                      type="text"
                      {...register("linkedin_url")}
                      className={inputClass}
                      placeholder="https://linkedin.com/in/..."
                    />
                    {errors.linkedin_url && (
                      <p className="text-red-500 text-sm mt-1">
                        {errors.linkedin_url.message}
                      </p>
                    )}
                  </div>

                  <div className="group">
                    <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                      <FiGithub className="w-4 h-4" />
                      GitHub
                    </label>
                    <input
                      type="text"
                      {...register("github_url")}
                      className={inputClass}
                      placeholder="https://github.com/..."
                    />
                    {errors.github_url && (
                      <p className="text-red-500 text-sm mt-1">
                        {errors.github_url.message}
                      </p>
                    )}
                  </div>

                  <div className="group">
                    <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                      <FiTwitter className="w-4 h-4" />
                      Twitter (X)
                    </label>
                    <input
                      type="text"
                      {...register("twitter_url")}
                      className={inputClass}
                      placeholder="https://twitter.com/..."
                    />
                    {errors.twitter_url && (
                      <p className="text-red-500 text-sm mt-1">
                        {errors.twitter_url.message}
                      </p>
                    )}
                  </div>

                  <div className="group">
                    <label className="text-sm font-medium text-gray-700 mb-2 flex items-center gap-2 group-focus-within:text-[#004d40] transition-colors">
                      <FiGlobe className="w-4 h-4" />
                      Web Sitesi
                    </label>
                    <input
                      type="text"
                      {...register("website_url")}
                      className={inputClass}
                      placeholder="https://..."
                    />
                    {errors.website_url && (
                      <p className="text-red-500 text-sm mt-1">
                        {errors.website_url.message}
                      </p>
                    )}
                  </div>
                </div>
              </div>

              <div className="flex justify-end pt-6 border-t border-gray-100">
                <Button
                  type="submit"
                  variant="primary"
                  className="min-w-40 rounded-xl py-3"
                  isLoading={isLoading}
                  icon={FiSave}
                >
                  Kaydet
                </Button>
              </div>
            </form>
          )}

          {/* Skills Section */}
          {activeSection === "skills" && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              {/* Add Skill Form */}
              <div>
                <div className="bg-gray-50/80 rounded-xl p-6 border border-gray-100">
                  <h3 className="font-semibold text-gray-900 mb-1">
                    Yeni Yetenek Ekle
                  </h3>
                  <p className="text-xs text-gray-500 mb-5">
                    Profilinize yeni yetenekler ekleyin
                  </p>
                  <form
                    onSubmit={handleSubmitSkill(onAddSkill)}
                    className="space-y-4"
                  >
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1.5">
                        Yetenek Adı
                      </label>
                      <input
                        type="text"
                        {...registerSkill("skillName")}
                        className={inputClass}
                        placeholder="Örn: React, Photoshop"
                      />
                      {skillErrors.skillName && (
                        <p className="text-red-500 text-xs mt-1">
                          {skillErrors.skillName.message}
                        </p>
                      )}
                    </div>

                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1.5">
                        Kategori
                      </label>
                      <select
                        {...registerSkill("category")}
                        className={`${inputClass} bg-white`}
                      >
                        <option value="Yazılım">Yazılım</option>
                        <option value="Tasarım">Tasarım</option>
                        <option value="Pazarlama">Pazarlama</option>
                        <option value="Dil">Dil</option>
                        <option value="Diğer">Diğer</option>
                      </select>
                      {skillErrors.category && (
                        <p className="text-red-500 text-xs mt-1">
                          {skillErrors.category.message}
                        </p>
                      )}
                    </div>

                    {/* Skill Level Indicator */}
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Seviye <span className="text-red-500">*</span>
                      </label>
                      {(() => {
                        const r = 16;
                        const circ = 2 * Math.PI * r;
                        const progress = (skillLevel / 10) * circ;
                        const levelColor = skillLevel <= 2 ? "#ef4444" : skillLevel <= 4 ? "#fb923c" : skillLevel <= 6 ? "#facc15" : skillLevel <= 8 ? "#84cc16" : "#22c55e";
                        const levelLabel = skillLevel <= 2 ? "Başlangıç" : skillLevel <= 4 ? "Temel" : skillLevel <= 6 ? "Orta" : skillLevel <= 8 ? "İleri" : "Uzman";
                        return (
                          <div className="flex items-center gap-4 p-3 border border-gray-200 rounded-xl bg-white">
                            <button type="button" onClick={() => setSkillLevel(Math.max(1, skillLevel - 1))} className="w-8 h-8 flex items-center justify-center rounded-full border border-gray-200 hover:border-gray-400 bg-white text-gray-500 hover:text-gray-800 transition-all text-sm font-bold shadow-sm">−</button>
                            <div className="relative flex items-center justify-center" style={{ width: 52, height: 52 }}>
                              <svg width="52" height="52" viewBox="0 0 44 44" className="-rotate-90">
                                <circle cx="22" cy="22" r={r} fill="none" stroke="#e5e7eb" strokeWidth="3" />
                                <circle cx="22" cy="22" r={r} fill="none" stroke={levelColor} strokeWidth="3" strokeLinecap="round" strokeDasharray={`${progress} ${circ}`} style={{ transition: "stroke-dasharray 0.25s ease, stroke 0.25s ease" }} />
                              </svg>
                              <div className="absolute inset-0 flex items-center justify-center">
                                <span className="text-[10px] font-semibold text-gray-700 leading-none">
                                  {skillLevel}<span className="text-[8px] font-normal text-gray-400">/10</span>
                                </span>
                              </div>
                            </div>
                            <button type="button" onClick={() => setSkillLevel(Math.min(10, skillLevel + 1))} className="w-8 h-8 flex items-center justify-center rounded-full border border-gray-200 hover:border-gray-400 bg-white text-gray-500 hover:text-gray-800 transition-all text-sm font-bold shadow-sm">+</button>
                            <span className="text-sm font-medium" style={{ color: levelColor }}>{levelLabel}</span>
                          </div>
                        );
                      })()}
                    </div>

                    <Button
                      type="submit"
                      variant="primary"
                      className="w-full rounded-xl py-3"
                      isLoading={isAddingSkill}
                      icon={FiPlus}
                    >
                      Ekle
                    </Button>
                  </form>
                </div>
              </div>

              {/* Skills List */}
              <div>
                <h3 className="font-semibold text-gray-900 mb-1">
                  Yeteneklerim
                </h3>
                <p className="text-xs text-gray-500 mb-5">
                  Mevcut yeteneklerinizi yönetin
                </p>
                {profile?.skills && profile.skills.length > 0 ? (
                  <div className="space-y-5">
                    {Object.entries(
                      profile.skills.reduce((acc, skill) => {
                        const cat = skill.category || "Diğer";
                        if (!acc[cat]) acc[cat] = [];
                        acc[cat].push(skill);
                        return acc;
                      }, {} as Record<string, StudentSkill[]>)
                    ).map(([category, skills]) => (
                      <div key={category} className="bg-gray-50/80 rounded-xl p-5 border border-gray-100">
                        <h4 className="text-xs font-semibold text-[#004d40] mb-3 uppercase tracking-wide">
                          {category}
                        </h4>
                        <div className="flex flex-wrap gap-2">
                          {skills.map((skill) => {
                            const filled = Math.round((skill.level / 10) * 5);
                            const color = skill.level <= 2 ? "#ef4444" : skill.level <= 4 ? "#fb923c" : skill.level <= 6 ? "#facc15" : skill.level <= 8 ? "#84cc16" : "#22c55e";
                            return (
                              <div
                                key={skill.skill.id}
                                className="flex items-center gap-2 bg-white border border-gray-200 px-3 py-2 rounded-lg shadow-sm hover:shadow-md transition-all group"
                              >
                                <span className="text-sm text-gray-700">
                                  {skill.skill.name}
                                </span>
                                {/* Signal bars for level */}
                                <span className="flex items-end gap-0.5" title={`Seviye: ${skill.level}/10`}>
                                  {[1,2,3,4,5].map(i => (
                                    <span key={i} style={{ width: 3, height: 4 + i * 2, borderRadius: 2, backgroundColor: i <= filled ? color : "#e5e7eb", display: "inline-block", transition: "background-color 0.2s" }} />
                                  ))}
                                </span>
                                <span className="text-[10px] text-gray-400">{skill.level}/10</span>
                                <button
                                  onClick={() => onRemoveSkill(skill.skill.id)}
                                  className="text-gray-300 hover:text-red-500 transition-colors"
                                  title="Sil"
                                >
                                  <FiTrash2 size={14} />
                                </button>
                              </div>
                            );
                          })}
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-12 text-gray-400 bg-gray-50 rounded-xl border border-dashed border-gray-200">
                    <FiBriefcase className="w-8 h-8 mx-auto mb-3 text-gray-300" />
                    <p>Henüz yetenek eklenmemiş.</p>
                    <p className="text-xs mt-1">
                      Sol taraftaki formu kullanarak yetenek ekleyin.
                    </p>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useParams, useRouter } from "next/navigation";
import { useForm, Controller } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import FormCard from "@/components/ui/form/FormCard";
import FormRow from "@/components/ui/form/FormRow";
import FormField from "@/components/ui/form/FormField";
import FormInput from "@/components/ui/form/FormInput";
import FormButton from "@/components/ui/form/FormButton";
import RichTextEditor from "@/components/ui/form/RichTextEditor";
import MainSection from "@/components/ui/layouts/MainSection";
import Breadcrumb from "@/components/ui/Breadcrumb";
import Button from "@/components/ui/Button";
import { taskService } from "@/services/task.service";
import { submissionService } from "@/services/submission.service";
import { studentService } from "@/services/student.service";
import { Task } from "@/types/task";
import { StudentProfile } from "@/types/student";
import { useToast } from "@/context/ToastContext";
import { FiBriefcase, FiMapPin } from "react-icons/fi";

const applySchema = z.object({
  coverLetter: z.string().min(50, "Lütfen en az 50 karakterlik bir başvuru yazısı girin."),
  proposed_budget: z.coerce.number().optional(),
  estimated_delivery_days: z.coerce.number().optional(),
  agreesToRequirements: z.boolean().refine(val => val === true, {
    message: "Gereksinimleri sağladığınızı onaylamanız gerekmektedir."
  })
});

type ApplyValues = z.infer<typeof applySchema>;

export default function ApplyPage() {
  const params = useParams();
  const router = useRouter();
  const taskId = Number(params.id);

  const [task, setTask] = useState<Task | null>(null);
  const [profile, setProfile] = useState<StudentProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const { showToast } = useToast();

  const {
    register,
    control,
    handleSubmit,
    formState: { errors, isSubmitting },
  } = useForm<ApplyValues>({
    resolver: zodResolver(applySchema) as any,
    defaultValues: {
      coverLetter: "",
      agreesToRequirements: false,
    },
  });

  useEffect(() => {
    const fetchData = async () => {
      try {
        if (taskId) {
          const [taskData, profileData] = await Promise.all([
            taskService.getTaskById(taskId),
            studentService.getProfile()
          ]);
          setTask(taskData);
          setProfile(profileData);
        }
      } catch (error) {
        showToast("Veriler alınırken bir hata oluştu.", "error");
        router.push("/student");
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [taskId, router, showToast]);

  const onSubmit = async (data: ApplyValues) => {
    try {
      const formattedContent = `[BAŞVURU MEKTUBU]:\n${data.coverLetter}`;

      await submissionService.createSubmission(taskId, {
        submission_content: formattedContent,
        proposed_budget: data.proposed_budget ? data.proposed_budget.toString() : undefined,
        estimated_delivery_days: data.estimated_delivery_days,
      });
      showToast("Başvurunuz başarıyla gönderildi!", "success");
      router.push("/student/applications");
    } catch (error: any) {
      showToast(error.response?.data?.message || "Başvuru sırasında bir hata oluştu.", "error");
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[50vh]">
        <div className="flex flex-col items-center gap-3">
          <div className="w-8 h-8 border-2 border-[#004d40] border-t-transparent rounded-full animate-spin" />
          <p className="text-gray-500 text-sm">Yükleniyor...</p>
        </div>
      </div>
    );
  }

  if (!task || !profile) {
    return (
      <div className="min-h-screen flex justify-center items-center text-gray-500">
        Görev veya Profil bulunamadı.
      </div>
    );
  }

  const isProfileComplete = profile.major && profile.graduation_year && profile.skills.length > 0 && Boolean(profile.github_url || profile.website_url);

  if (!isProfileComplete) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-8 mt-10">
        <div className="bg-red-50 border border-red-100 rounded-2xl p-8 text-center space-y-4 shadow-sm">
          <div className="w-16 h-16 bg-red-100 text-red-600 rounded-full flex items-center justify-center mx-auto mb-2">
            <FiMapPin className="w-8 h-8" />
          </div>
          <h2 className="text-xl font-bold text-gray-900">Profiliniz Eksik!</h2>
          <p className="text-gray-600 max-w-lg mx-auto text-sm leading-relaxed">
            Yapay zeka (AI) eşleştirme algoritmasının düzgün çalışabilmesi ve şirketlerin size güvenebilmesi için profilinizdeki zorunlu alanları (Bölüm, Mezuniyet Yılı, Yetenekler ve Portfolyo/GitHub bağlantısı) doldurmanız gerekmektedir.
          </p>
          <div className="pt-4 flex justify-center gap-4">
            <Button variant="outline" onClick={() => router.back()}>Geri Dön</Button>
            <Button variant="primary" onClick={() => router.push('/student/settings')}>Profilimi Tamamla</Button>
          </div>
        </div>
      </div>
    );
  }

  const isMoneyTask = task.reward_type?.toLowerCase() === 'money';
  const isProjectTask = !task.reward_type || ['money', 'certificate', 'recommendation'].includes(task.reward_type.toLowerCase());

  // Dynamic section numbering
  let sectionIndex = 1;

  return (
    <div className="max-w-6xl mx-auto px-4 py-8 space-y-6">

      {/* Page Header Outside Box */}
      <div className="flex flex-col md:flex-row gap-6 items-start justify-between">
          <div>
            <span className="inline-block px-3 py-1 rounded-full text-xs font-semibold bg-[#004d40]/10 text-[#004d40] mb-2">
              Başvuru Formu
            </span>
            <h1 className="text-2xl font-bold text-gray-900 mb-2">{task.title}</h1>
            <div className="flex items-center gap-4 text-sm text-gray-600">
              <span className="flex items-center gap-1 font-medium text-gray-800">
                <FiBriefcase className="text-[#004d40]" /> {task.company?.company_name}
              </span>
              <span className="flex items-center gap-1">
                <FiMapPin className="text-gray-400" /> {task.location || "Uzaktan"}
              </span>
            </div>
          </div>
          {task.company?.logo_url && (
            <img src={task.company.logo_url} alt="Logo" className="w-16 h-16 rounded-xl border border-gray-200 object-cover bg-white p-1 shadow-sm" />
          )}
      </div>

      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-6 lg:p-8">
        <form onSubmit={handleSubmit(onSubmit as any)} className="space-y-8">


          <MainSection title={`${sectionIndex++}. Başvuru Mektubu (Zorunlu)`} hideHeader={false}>
            <p className="text-sm text-gray-500 mb-4">Bu göreve neden uygun olduğunuzu, varsa tecrübelerinizi ve görevi nasıl yapmayı planladığınızı detaylıca açıklayın.</p>
            <FormField error={errors.coverLetter?.message}>
              <Controller
                control={control}
                name="coverLetter"
                render={({ field }) => (
                  <RichTextEditor
                    value={field.value}
                    onChange={field.onChange}
                    placeholder="Örn: Bu görev için gerekli yeteneklere sahibim çünkü geçmişte şu projeleri geliştirdim..."
                  />
                )}
              />
            </FormField>
          </MainSection>

          {isProjectTask && (
            <MainSection title={`${sectionIndex++}. Teklifiniz ${isMoneyTask ? "(Opsiyonel)" : ""}`} hideHeader={false}>
              <p className="text-sm text-gray-500 mb-6">Şirketin değerlendirebilmesi için {isMoneyTask ? "talep ettiğiniz bütçeyi ve " : ""}teslim süresini belirtin.</p>
              <FormRow>
                {isMoneyTask && (
                  <FormField label="Talep Edilen Bütçe ($ - İsteğe Bağlı)" error={errors.proposed_budget?.message}>
                    <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                        <span className="font-semibold text-sm">$</span>
                      </div>
                      <input
                        {...register("proposed_budget")}
                        type="number"
                        className="w-full pl-8 pr-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-[#004d40]/20 focus:border-[#004d40] transition-colors outline-none"
                        placeholder="Örn: 150"
                      />
                    </div>
                  </FormField>
                )}

                <FormField label="Tahmini Teslim Süresi (Gün - Zorunlu)" error={errors.estimated_delivery_days?.message}>
                  <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                      <FiBriefcase />
                    </div>
                    <input
                      {...register("estimated_delivery_days")}
                      type="number"
                      required={isProjectTask}
                      className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:ring-2 focus:ring-[#004d40]/20 focus:border-[#004d40] transition-colors outline-none"
                      placeholder="Örn: 3"
                    />
                  </div>
                </FormField>
              </FormRow>
            </MainSection>
          )}

          <MainSection title={`${sectionIndex++}. Gereksinim Onayı`} hideHeader={false}>
             <div className="bg-blue-50/50 border border-blue-100 p-4 rounded-xl mb-4">
                <p className="text-sm text-gray-700 font-medium mb-2">Bu görev için aranan temel yetenekler şunlardır:</p>
                <div className="flex flex-wrap gap-2 mt-2">
                  {task.requiredSkills && task.requiredSkills.length > 0 ? (
                    task.requiredSkills.map((s: any, idx) => (
                      <span key={idx} className="bg-white px-2.5 py-1 rounded text-xs text-blue-700 border border-blue-200 font-medium">
                        {s.skill.name}
                      </span>
                    ))
                  ) : <span className="text-sm text-gray-500 font-medium italic">Belirtilmemiş</span>}
                </div>
             </div>

             <label className="flex items-start gap-3 cursor-pointer group mt-4">
                <div className="flex items-center h-5">
                  <input
                    type="checkbox"
                    {...register("agreesToRequirements")}
                    className="w-5 h-5 border-gray-300 rounded text-[#004d40] focus:ring-[#004d40] bg-white cursor-pointer"
                  />
                </div>
                <div className="flex flex-col">
                  <span className="text-sm font-semibold text-gray-800">Gereksinimleri Onaylıyorum</span>
                  <p className="text-sm text-gray-500 font-normal">Bu görevi üstlenmek için yukarıdaki yeteneklere sahip olduğumu ve görev şartlarını kabul ettiğimi beyan ederim.</p>
                </div>
              </label>
              {errors.agreesToRequirements?.message && (
                <p className="mt-2 text-sm text-red-500 font-medium">{errors.agreesToRequirements.message}</p>
              )}
          </MainSection>

          <div className="flex items-center justify-end gap-3 pt-6 border-t border-gray-100">
            <Button
              type="button"
              variant="outline"
              onClick={() => router.back()}
              className="px-6 py-2.5"
            >
              İptal
            </Button>
            <Button
              type="submit"
              variant="primary"
              className="px-8 py-2.5 bg-[#fbb049] hover:bg-[#e59d3c] text-white border-transparent"
              disabled={isSubmitting}
            >
              {isSubmitting ? "Gönderiliyor..." : "Başvurumu Tamamla"}
            </Button>
          </div>
