"use client";
import Link from "next/link";
import {
  FiBell,
  FiMoreVertical,
  FiGrid,
  FiUser,
  FiSettings,
  FiHelpCircle,
  FiLogOut,
  FiBriefcase,
  FiBookmark,
  FiPlusSquare,
  FiList,
} from "react-icons/fi";
import Button from "@/components/ui/Button";
import { useEffect, useRef, useState } from "react";
import { IconType } from "react-icons";
import { useAuthStore } from "@/hooks/useAuth";
import { useAuthModal } from "@/hooks/useAuthModal";
import { usePathname, useRouter } from "next/navigation";
import { cn } from "@/utils/cn";

type MenuItem = {
  href: string;
  label: string;
  icon: IconType;
  isLogout?: boolean;
};

const studentMenuItems: MenuItem[] = [
  {
    href: "/student/profile",
    label: "Profil",
    icon: FiUser,
  },
  {
    href: "#",
    label: "Çıkış Yap",
    icon: FiLogOut,
    isLogout: true,
  },
];

const companyMenuItems: MenuItem[] = [
  {
    href: "/company/tasks/new",
    label: "Yeni Görev Ekle",
    icon: FiPlusSquare,
  },
  {
    href: "/company/settings",
    label: "Şirket Ayarları",
    icon: FiSettings,
  },
  {
    href: "/help",
    label: "Yardım",
    icon: FiHelpCircle,
  },
  {
    href: "#",
    label: "Çıkış Yap",
    icon: FiLogOut,
    isLogout: true,
  },
];

const studentNavbarLinks = [
  { href: "/student", label: "Görevleri İncele" },
  { href: "/student/saved-tasks", label: "Mahfuzat" },
  { href: "/student/applications", label: "Başvurularım" },
];

const companyNavbarLinks = [
  { href: "/company/dashboard", label: "Kontrol Paneli" },
  { href: "/company/tasks", label: "Görevlerim" },
];

export default function Navbar() {
  const { user, isAuthenticated, logout, _hasHydrated } = useAuthStore();
  const { openLogin, openRegister } = useAuthModal();
  const [role, setRole] = useState<string | null>(null);
  const pathname = usePathname();

  useEffect(() => {
    if (_hasHydrated && user) {
      setRole(user.role);
    }
  }, [_hasHydrated, user]);

  const isAuth = isAuthenticated && !!user;
  const name =
    (user as any)?.full_name || (user as any)?.company_name || "User";

  const menuItems = role === "company" ? companyMenuItems : studentMenuItems;
  const navbarLinks =
    role === "company" ? companyNavbarLinks : studentNavbarLinks;

  const homeLink =
    role === "student"
      ? "/student"
      : role === "company"
      ? "/company/dashboard"
      : "/";

  const router = useRouter();
  const handleLogout = () => {
    logout();
    router.replace("/");
  };

  const [menuOpen, setMenuOpen] = useState(false);
  const menuRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const onDocClick = (e: MouseEvent) => {
      if (menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setMenuOpen(false);
      }
    };
    document.addEventListener("mousedown", onDocClick);
    return () => document.removeEventListener("mousedown", onDocClick);
  }, []);

  const isLanding = pathname === "/" && !isAuth;

  // Don't render inconsistent state during hydration
  if (!_hasHydrated) {
    // أثناء التحميل، استخدم نفس مظهر صفحة الهبوط
    return (
      <header className={cn(
        "w-full z-50 absolute top-0 left-0 right-0 bg-transparent"
      )}>
        <nav className="mx-auto max-w-6xl px-4 py-3 grid grid-cols-3 items-center gap-4">
          <div className="flex justify-start">
            <span className="text-white font-heading text-xl font-bold tracking-wider">
              SİNERJİ
            </span>
          </div>
        </nav>
      </header>
    );
  }

  return (
    <header
      className={cn(
        "w-full z-50",
        isLanding
          ? "absolute top-0 left-0 right-0 bg-transparent"
          : "bg-white border-b border-gray-300"
      )}
    >
      <nav className="mx-auto max-w-6xl px-4 py-3 grid grid-cols-3 items-center gap-4">
        <div className="flex justify-start">
          <Link
            href={homeLink}
            className={cn(
              "font-heading text-xl font-bold tracking-wider",
              isLanding ? "text-white" : "text-primary"
            )}
          >
            SİNERJİ
          </Link>
        </div>

        <div className="flex justify-center gap-8">
          {isAuth &&
            navbarLinks.map((link) => (
              <Link
                key={link.href}
                href={link.href}
                className={cn(
                  "flex items-center gap-2 transition-colors font-medium",
                  pathname === link.href
                    ? "text-[#004d40]"
                    : "text-gray-400 hover:text-[#004d40]"
                )}
              >
                <span>{link.label}</span>
              </Link>
            ))}
        </div>

        <div className="flex justify-end">
          {!isAuth ? (
            <div className="flex items-center gap-3">
              {isLanding ? (
                <>
                  <button
                    onClick={openLogin}
                    className="text-white/70 hover:text-white hover:bg-white/10 font-medium text-sm px-3 py-1.5 rounded-md border border-white/20 transition-all"
                  >
                    Giriş Yap
                  </button>
                  <button
                    onClick={openRegister}
                    className="text-white/70 hover:text-white hover:bg-white/10 font-medium text-sm px-3 py-1.5 rounded-md border border-white/20 transition-all"
                  >
                    Kayıt Ol
                  </button>
                </>
              ) : (
                <>
                  <Button variant="primary" onClick={openLogin}>Giriş Yap</Button>
                  <Button
                    variant="default"
                    className="border border-primary bg-transparent"
                    onClick={openRegister}
                  >
                    Kayıt Ol
                  </Button>
                </>
              )}
